#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#define RD_WG_SIZE_0_0 508
#include "common.h"

extern "C" long long get_time();
extern "C" void setdevice(void);
extern "C" void checkCUDAError(const char *msg);

static inline void cuda_check(cudaError_t err, const char *msg) {
	if (err != cudaSuccess) {
		printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString(err));
		fflush(NULL);
		exit(EXIT_FAILURE);
	}
}

static long infer_records_mem(record *records, knode *knodes, long knodes_elem) {
	(void)records;
	long max_record_index = -1;
	for (long i = 0; i < knodes_elem; i++) {
		if (knodes[i].is_leaf) {
			int end = knodes[i].num_keys - 1;
			for (int j = 1; j < end; j++) {
				if (knodes[i].indices[j] > max_record_index) {
					max_record_index = knodes[i].indices[j];
				}
			}
		}
	}
	if (max_record_index < 0) return 0;
	return (max_record_index + 1) * (long)sizeof(record);
}

__global__ void search_kernel(record *records,
							  knode *knodes,
							  long knodes_elem,
							  int order,
							  long maxheight,
							  int count,
							  long *currKnode,
							  long *offset,
							  int *keys,
							  record *ans)
{
	int bid = blockIdx.x * blockDim.x + threadIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = order < 1024 ? order : 1024;
	int i, thid;

	for (i = 0; i < maxheight; i++) {
		for (thid = 0; thid < threadsPerBlock; thid++) {
			if ((knodes[currKnode[bid]].keys[thid]) <= keys[bid] &&
				(knodes[currKnode[bid]].keys[thid + 1] > keys[bid])) {
				if (knodes[offset[bid]].indices[thid] < knodes_elem) {
					offset[bid] = knodes[offset[bid]].indices[thid];
				}
			}
		}
		currKnode[bid] = offset[bid];
	}

	for (thid = 0; thid < threadsPerBlock; thid++) {
		if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
			ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
		}
	}
}

static void launch_search_cuda(record *records,
							   long records_mem,
							   knode *knodes,
							   long knodes_elem,
							   long knodes_mem,
							   int order,
							   long maxheight,
							   int count,
							   long *currKnode,
							   long *offset,
							   int *keys,
							   record *ans)
{
	long long time0 = get_time();
	long long time1;
	long long time2;

	setdevice();
	time1 = get_time();

	record *d_records = NULL;
	knode *d_knodes = NULL;
	long *d_currKnode = NULL;
	long *d_offset = NULL;
	int *d_keys = NULL;
	record *d_ans = NULL;

	if (records_mem > 0) {
		cuda_check(cudaMalloc((void **)&d_records, (size_t)records_mem), "cudaMalloc d_records");
		cuda_check(cudaMemcpy(d_records, records, (size_t)records_mem, cudaMemcpyHostToDevice), "cudaMemcpy H2D records");
	}
	if (knodes_mem > 0) {
		cuda_check(cudaMalloc((void **)&d_knodes, (size_t)knodes_mem), "cudaMalloc d_knodes");
		cuda_check(cudaMemcpy(d_knodes, knodes, (size_t)knodes_mem, cudaMemcpyHostToDevice), "cudaMemcpy H2D knodes");
	}

	cuda_check(cudaMalloc((void **)&d_currKnode, (size_t)count * sizeof(long)), "cudaMalloc d_currKnode");
	cuda_check(cudaMalloc((void **)&d_offset, (size_t)count * sizeof(long)), "cudaMalloc d_offset");
	cuda_check(cudaMalloc((void **)&d_keys, (size_t)count * sizeof(int)), "cudaMalloc d_keys");
	cuda_check(cudaMalloc((void **)&d_ans, (size_t)count * sizeof(record)), "cudaMalloc d_ans");

	cuda_check(cudaMemcpy(d_currKnode, currKnode, (size_t)count * sizeof(long), cudaMemcpyHostToDevice), "cudaMemcpy H2D currKnode");
	cuda_check(cudaMemcpy(d_offset, offset, (size_t)count * sizeof(long), cudaMemcpyHostToDevice), "cudaMemcpy H2D offset");
	cuda_check(cudaMemcpy(d_keys, keys, (size_t)count * sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy H2D keys");
	cuda_check(cudaMemcpy(d_ans, ans, (size_t)count * sizeof(record), cudaMemcpyHostToDevice), "cudaMemcpy H2D ans");

	int threads = 256;
	int blocks = (count + threads - 1) / threads;
	search_kernel<<<blocks, threads>>>(d_records, d_knodes, knodes_elem, order, maxheight, count, d_currKnode, d_offset, d_keys, d_ans);
	checkCUDAError("search_kernel");
	cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize search_kernel");

	cuda_check(cudaMemcpy(currKnode, d_currKnode, (size_t)count * sizeof(long), cudaMemcpyDeviceToHost), "cudaMemcpy D2H currKnode");
	cuda_check(cudaMemcpy(offset, d_offset, (size_t)count * sizeof(long), cudaMemcpyDeviceToHost), "cudaMemcpy D2H offset");
	cuda_check(cudaMemcpy(ans, d_ans, (size_t)count * sizeof(record), cudaMemcpyDeviceToHost), "cudaMemcpy D2H ans");

	cudaFree(d_records);
	cudaFree(d_knodes);
	cudaFree(d_currKnode);
	cudaFree(d_offset);
	cudaFree(d_keys);
	cudaFree(d_ans);

	time2 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
		   (float)(time1 - time0) / 1000000,
		   (float)(time1 - time0) / (float)(time2 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
		   (float)(time2 - time1) / 1000000,
		   (float)(time2 - time1) / (float)(time2 - time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

void kernel_cpu(int cores_arg,
				record *records,
				knode *knodes,
				long knodes_elem,
				int order,
				long maxheight,
				int count,
				long *currKnode,
				long *offset,
				int *keys,
				record *ans)
{
	(void)cores_arg;
	long records_mem = infer_records_mem(records, knodes, knodes_elem);
	long knodes_mem = knodes_elem * (long)sizeof(knode);

	launch_search_cuda(records,
					   records_mem,
					   knodes,
					   knodes_elem,
					   knodes_mem,
					   order,
					   maxheight,
					   count,
					   currKnode,
					   offset,
					   keys,
					   ans);
}

extern "C" void kernel_gpu_cuda_wrapper(record *records,
										long records_mem,
										knode *knodes,
										long knodes_elem,
										long knodes_mem,
										int order,
										long maxheight,
										int count,
										long *currKnode,
										long *offset,
										int *keys,
										record *ans)
{
	launch_search_cuda(records,
					   records_mem,
					   knodes,
					   knodes_elem,
					   knodes_mem,
					   order,
					   maxheight,
					   count,
					   currKnode,
					   offset,
					   keys,
					   ans);
}

