		i->next = next;
		i->pred = NULL;
		l->head = i;
		next->pred = i;
	} else {
		i->next = next;
		i->pred = next->pred;
		next->pred->next = i;
		next->pred = i;
	}
	l->length++;
}

void list_insert_after(list_t *l, list_item_t *pred, void *v) {
	list_item_t *i = (list_item_t *)malloc(sizeof(*i));
	list_item_init(i, v);
	if (l->tail == pred) {
		i->pred = pred;
		i->next = NULL;
		l->tail = i;
		pred->next = i;
	} else {
		i->pred = pred;
		i->next = pred->next;
		pred->next->pred = i;
		pred->next = i;
	}
	l->length++;
}

void list_insert_sorted(list_t *l, void *v) {
	list_item_t *itr;
	list_item_t *i = (list_item_t *)malloc(sizeof(*i));
	list_item_init(i, v);
	if (l->head) {
		for (itr = l->head; itr && l->compare(list_item_get_datum(i), list_item_get_datum(itr)) < 0; itr = itr->next)
			;
		if (itr) {
			i->next = itr;
			i->pred = itr->pred;
			itr->pred = i;
			i->pred->next = i;
		} else {
			l->tail->next = i;
			i->pred = l->tail;
			i->next = NULL;
			l->tail = i;
		}
	} else {
		l->head = l->tail = i;
		i->pred = i->next = NULL;
	}
	l->length++;
}

void list_remove_item(list_t *l, list_item_t *i) {
	if (i == l->head) {
		l->head = l->head->next;
		if (l->head) l->head->pred = NULL;
		else l->tail = NULL;
	} else if (i == l->tail) {
		l->tail = l->tail->pred;
		l->tail->next = NULL;
	} else {
		i->pred->next = i->next;
		i->next->pred = i->pred;
	}
	l->length--;
	list_item_delete(i, l->datum_delete);
}

void list_remove_head(list_t *l) {
	list_remove_item(l, l->head);
}

void list_remove_tail(list_t *l) {
	list_remove_item(l, l->tail);
}

list_item_t *list_find_item(list_t *l, void *datum) {
	list_item_t *li;
	for (li = l->head; li && l->compare(datum, list_item_get_datum(li)); li = li->next)
		;
	return li;
}

list_item_t *list_get_head_item(list_t *l) {
	return l->head;
}

list_item_t *list_get_tail_item(list_t *l) {
