void *list_find(list_t *l, void *datum) {
	list_item_t *li;
	for (li = l->head; li && l->compare(datum, list_item_get_datum(li)); li = li->next)
		;
	return li ? li->datum : NULL;
}

void *list_get_head(list_t *l) {
