extern "C" void checkCUDAError(const char *msg);

__global__
static void bpt_find_kernel(record *records,
							knode *knodes,
							long knodes_elem,
							int order,
							long maxheight,
							int count,
							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{
	int bid = blockIdx.x * blockDim.x + threadIdx.x;
	if (bid >= count) return;

	long curr = currKnode[bid];
	long off = offset[bid];
	int key = keys[bid];
	int threadsPerBlock = order < 1024 ? order : 1024;

	for (long i = 0; i < maxheight; i++) {
		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if ((knodes[curr].keys[thid]) <= key && (knodes[curr].keys[thid + 1] > key)) {
				if (knodes[off].indices[thid] < knodes_elem) {
					off = knodes[off].indices[thid];
				}
			}
		}
		curr = off;
	}

	for (int thid = 0; thid < threadsPerBlock; thid++) {
		if (knodes[curr].keys[thid] == key) {
			ans[bid].value = records[knodes[curr].indices[thid]].value;
		}
	}

	currKnode[bid] = curr;
	offset[bid] = off;
}

__global__
static void bpt_range_kernel(knode *knodes,
							 long knodes_elem,
							 int order,
							 long maxheight,
							 int count,
							 long *currKnode,
							 long *offset,
							 long *lastKnode,
							 long *offset_2,
