        cudaMemcpy(&stop_int, d_stop, sizeof(int), cudaMemcpyDeviceToHost);
        stop = (stop_int != 0);
        k++;
    } while (stop);

#ifdef OPEN
    auto end_time = std::chrono::high_resolution_clock::now();
    double elapsed =
        std::chrono::duration<double>(end_time - start_time).count();
    printf("Compute time: %lf\n", elapsed);
