    size_t nodes_bytes_node = (no_of_nodes > 0) ? sizeof(Node_t2) * (size_t)no_of_nodes : sizeof(Node_t2);
    size_t nodes_bytes_bool = (no_of_nodes > 0) ? sizeof(bool) * (size_t)no_of_nodes : sizeof(bool);
