        cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(bool) * (size_t)no_of_nodes, cudaMemcpyHostToDevice);
        cudaMemcpy(d_cost, h_cost, sizeof(int) * (size_t)no_of_nodes, cudaMemcpyHostToDevice);
    }
    if (edge_list_size > 0) {
        cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int) * (size_t)edge_list_size, cudaMemcpyHostToDevice);
    }

    int k = 0;
    (void)k;
    double start_time = omp_get_wtime_t2();

    bool stop;
    int threads = 256;
    int blocks = (no_of_nodes + threads - 1) / threads;
    do {
        stop = false;
        int stop_int = 0;
        cudaMemcpy(d_stop, &stop_int, sizeof(int), cudaMemcpyHostToDevice);

        if (no_of_nodes > 0) {
