                d_stop);
        }

        cudaMemcpy(&stop_int, d_stop, sizeof(int), cudaMemcpyDeviceToHost);
        stop = (stop_int != 0);
        k++;
    } while (stop);

    double end_time = omp_get_wtime_t2();
    printf("Compute time: %lf\n", (end_time - start_time));

    if (no_of_nodes > 0) {
        cudaMemcpy(h_cost, d_cost, sizeof(int) * (size_t)no_of_nodes, cudaMemcpyDeviceToHost);
    }

