#include <cuda_runtime.h>

#include <iostream>
#include <fstream>
#include <cmath>
#include <chrono>
#include <cstdio>
#include <cstdlib>

#ifndef block_length
#define block_length 192
#endif

#define GAMMA 1.4
#define iterations 2000

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2
#define deg_angle_of_attack 0.0f

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

#define CUDA_CHECK(call) do { \
    cudaError_t err__ = (call); \
    if (err__ != cudaSuccess) { \
        std::fprintf(stderr, "CUDA error: %s\n", cudaGetErrorString(err__)); \
        std::exit(EXIT_FAILURE); \
    } \
} while(0)

template <typename T>
T* alloc(int N)
{
    T* t = nullptr;
    CUDA_CHECK(cudaMalloc((void**)&t, sizeof(T) * N));
    return t;
}

template <typename T>
void dealloc(T* array)
{
    CUDA_CHECK(cudaFree((void*)array));
}

template <typename T>
void copy(T* dst, T* src, int N)
{
    CUDA_CHECK(cudaMemcpy((void*)dst, (void*)src, sizeof(T) * N, cudaMemcpyDeviceToDevice));
}

template <typename T>
void upload(T* dst, T* src, int N)
{
    CUDA_CHECK(cudaMemcpy((void*)dst, (void*)src, sizeof(T) * N, cudaMemcpyHostToDevice));
}

template <typename T>
void download(T* dst, T* src, int N)
{
    CUDA_CHECK(cudaMemcpy((void*)dst, (void*)src, sizeof(T) * N, cudaMemcpyDeviceToHost));
}

void dump(float* variables, int nel, int nelr)
{
