	pub.in2_sub_cumh_sel_collow = 1 + pub.in_mod_cols;
	pub.in2_sub_cumh_sel_colhig = pub.in2_sub_cols - 1;
	pub.in2_sub_cumh_sel2_rowlow = 1;
	pub.in2_sub_cumh_sel2_rowhig = pub.in2_sub_rows;
	pub.in2_sub_cumh_sel2_collow = 1;
	pub.in2_sub_cumh_sel2_colhig = pub.in2_sub_cols - pub.in_mod_cols - 1;
	pub.in2_sub2_sqr_rows = pub.in2_sub_cumh_sel_rowhig - pub.in2_sub_cumh_sel_rowlow + 1;
	pub.in2_sub2_sqr_cols = pub.in2_sub_cumh_sel_colhig - pub.in2_sub_cumh_sel_collow + 1;
	pub.in2_sub2_sqr_elem = pub.in2_sub2_sqr_rows * pub.in2_sub2_sqr_cols;
	pub.in2_sub2_sqr_mem = sizeof(fp) * pub.in2_sub2_sqr_elem;

	for(i=0; i<pub.allPoints; i++){
		cuda_check(cudaMallocManaged((void**)&priv[i].d_in2_sub2_sqr, pub.in2_sub2_sqr_mem), "cudaMallocManaged d_in2_sub2_sqr");
	}

	pub.tMask_rows = pub.in_mod_rows + (pub.sSize+1+pub.sSize) - 1;
	pub.tMask_cols = pub.tMask_rows;
	pub.tMask_elem = pub.tMask_rows * pub.tMask_cols;
	pub.tMask_mem = sizeof(fp) * pub.tMask_elem;

	for(i=0; i<pub.allPoints; i++){
		cuda_check(cudaMallocManaged((void**)&priv[i].d_tMask, pub.tMask_mem), "cudaMallocManaged d_tMask");
	}

	pub.mask_rows = pub.maxMove;
	pub.mask_cols = pub.mask_rows;
	pub.mask_elem = pub.mask_rows * pub.mask_cols;
	pub.mask_mem = sizeof(fp) * pub.mask_elem;

	pub.mask_conv_rows = pub.tMask_rows;
	pub.mask_conv_cols = pub.tMask_cols;
	pub.mask_conv_elem = pub.mask_conv_rows * pub.mask_conv_cols;
	pub.mask_conv_mem = sizeof(fp) * pub.mask_conv_elem;
	pub.mask_conv_ioffset = (pub.mask_rows-1)/2;
	if((pub.mask_rows-1) % 2 > 0.5){
		pub.mask_conv_ioffset = pub.mask_conv_ioffset + 1;
	}
	pub.mask_conv_joffset = (pub.mask_cols-1)/2;
	if((pub.mask_cols-1) % 2 > 0.5){
		pub.mask_conv_joffset = pub.mask_conv_joffset + 1;
	}

	for(i=0; i<pub.allPoints; i++){
		cuda_check(cudaMallocManaged((void**)&priv[i].d_mask_conv, pub.mask_conv_mem), "cudaMallocManaged d_mask_conv");
	}

	cuda_check(cudaMallocManaged((void**)&pub.d_frame, pub.frame_mem), "cudaMallocManaged d_frame");

	printf("frame progress: ");
	fflush(NULL);

	for(pub.frame_no=0; pub.frame_no<frames_processed; pub.frame_no++){

		fp* host_frame = get_frame(pub.d_frames,
						pub.frame_no,
						0,
						0,
						1);

		memcpy(pub.d_frame, host_frame, pub.frame_mem);

		launch_kernel(pub, priv);

		free(host_frame);

		printf("%d ", pub.frame_no);
		fflush(NULL);

	}

	cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize final");

	printf("\n");
	fflush(NULL);

#ifdef OUTPUT
	write_data(	(char*)"result.txt",
			pub.frames,
			frames_processed,
			pub.endoPoints,
			pub.d_tEndoRowLoc,
			pub.d_tEndoColLoc,
			pub.epiPoints,
			pub.d_tEpiRowLoc,
			pub.d_tEpiColLoc);
#endif

	cudaFree(pub.d_endoRow);
	cudaFree(pub.d_endoCol);
	cudaFree(pub.d_tEndoRowLoc);
	cudaFree(pub.d_tEndoColLoc);
	cudaFree(pub.d_endoT);

	cudaFree(pub.d_epiRow);
	cudaFree(pub.d_epiCol);
	cudaFree(pub.d_tEpiRowLoc);
	cudaFree(pub.d_tEpiColLoc);
	cudaFree(pub.d_epiT);

	for(i=0; i<pub.allPoints; i++){
		free(priv[i].in_partial_sum);
		free(priv[i].in_sqr_partial_sum);
		free(priv[i].par_max_val);
		free(priv[i].par_max_coo);

		cudaFree(priv[i].d_in2);
		cudaFree(priv[i].d_in2_sqr);

		cudaFree(priv[i].d_in_mod);
		cudaFree(priv[i].d_in_sqr);

		cudaFree(priv[i].d_conv);

		cudaFree(priv[i].d_in2_pad);

		cudaFree(priv[i].d_in2_sub);

		cudaFree(priv[i].d_in2_sub2_sqr);

		cudaFree(priv[i].d_tMask);
		cudaFree(priv[i].d_mask_conv);
	}

	cudaFree(pub.d_frame);
	cudaFree(priv);

	return 0;

}

