}

__global__ void kernel_cuda(public_struct pub, private_struct* priv){

	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if (tid >= pub.allPoints) {
		return;
	}

	private_struct p = priv[tid];

	int ei_new;
	fp* d_in = NULL;
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic;
	int jc;
	int jp1;
	int ja1, ja2;
	int ip1;
	int ia1, ia2;
	int ja, jb;
	int ia, ib;
	fp s;
	int i;
	int j;
	int row;
	int col;
	int ori_row;
	int ori_col;
	int position;
	fp sum;
	int pos_ori;
	fp temp;
	fp temp2;
	int location;
	int cent;
	int tMask_row;
	int tMask_col;
	fp fin_max_val = 0;
	int fin_max_coo = 0;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	fp in_final_sum;
	fp in_sqr_final_sum;
	fp mean;
	fp mean_sqr;
	fp variance;
	fp deviation;
	fp denomT;
	int pointer;
	int ori_pointer;
	int loc_pointer;
	int ei_mod;

	(void)ic;
	(void)jc;
	(void)location;
	(void)ei_mod;

	if(pub.frame_no == 0){

		pointer = p.point_no * pub.frames + pub.frame_no;
		p.d_tRowLoc[pointer] = p.d_Row[p.point_no];
		p.d_tColLoc[pointer] = p.d_Col[p.point_no];

		d_in = &p.d_T[p.in_pointer];

		for(col = 0; col < pub.in_mod_cols; col++){
			for(row = 0; row < pub.in_mod_rows; row++){

				ori_row = p.d_Row[p.point_no] - 25 + row - 1;
				ori_col = p.d_Col[p.point_no] - 25 + col - 1;
				ori_pointer = ori_col * pub.frame_rows + ori_row;

				d_in[col * pub.in_mod_rows + row] = pub.d_frame[ori_pointer];

			}
		}

	}

	if(pub.frame_no != 0){

		in2_rowlow = p.d_Row[p.point_no] - pub.sSize;
		in2_collow = p.d_Col[p.point_no] - pub.sSize;

		for(col = 0; col < pub.in2_cols; col++){
			for(row = 0; row < pub.in2_rows; row++){

				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				temp = pub.d_frame[ori_col * pub.frame_rows + ori_row];
				p.d_in2[col * pub.in2_rows + row] = temp;
				p.d_in2_sqr[col * pub.in2_rows + row] = temp * temp;

			}
		}

		d_in = &p.d_T[p.in_pointer];

		for(col = 0; col < pub.in_mod_cols; col++){
			for(row = 0; row < pub.in_mod_rows; row++){

				rot_row = (pub.in_mod_rows - 1) - row;
				rot_col = (pub.in_mod_rows - 1) - col;
				pointer = rot_col * pub.in_mod_rows + rot_row;

				temp = d_in[pointer];
				p.d_in_mod[col * pub.in_mod_rows + row] = temp;
				p.d_in_sqr[pointer] = temp * temp;

			}
		}

		in_final_sum = 0;
		for(i = 0; i < pub.in_mod_elem; i++){
			in_final_sum = in_final_sum + d_in[i];
		}

		in_sqr_final_sum = 0;
		for(i = 0; i < pub.in_mod_elem; i++){
			in_sqr_final_sum = in_sqr_final_sum + p.d_in_sqr[i];
		}

		mean = in_final_sum / pub.in_mod_elem;
		mean_sqr = mean * mean;
		variance  = (in_sqr_final_sum / pub.in_mod_elem) - mean_sqr;
		deviation = sqrtf(variance);

		denomT = sqrtf((fp)(pub.in_mod_elem - 1)) * deviation;

		for(col = 1; col <= pub.conv_cols; col++){

			j = col + pub.joffset;
			jp1 = j + 1;
			if(pub.in2_cols < jp1){
				ja1 = jp1 - pub.in2_cols;
			}
			else{
				ja1 = 1;
