				for(ja = ja1; ja <= ja2; ja++){
					jb = jp1 - ja;
					for(ia = ia1; ia <= ia2; ia++){
						ib = ip1 - ia;
						s = s + p.d_in_mod[pub.in_mod_rows * (ja - 1) + ia - 1] * p.d_in2[pub.in2_rows * (jb - 1) + ib - 1];
