		}

		for(ei_new = 0; ei_new < pub.in2_pad_cols; ei_new++){

			pos_ori = ei_new * pub.in2_pad_rows;

			sum = 0;
			for(position = pos_ori; position < pos_ori + pub.in2_pad_rows; position = position + 1){
				p.d_in2_pad[position] = p.d_in2_pad[position] + sum;
				sum = p.d_in2_pad[position];
			}

		}

		for(col = 0; col < pub.in2_sub_cols; col++){
			for(row = 0; row < pub.in2_sub_rows; row++){

				ori_row = row + pub.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + pub.in2_pad_cumv_sel_collow - 1;
				temp = p.d_in2_pad[ori_col * pub.in2_pad_rows + ori_row];

				ori_row = row + pub.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + pub.in2_pad_cumv_sel2_collow - 1;
				temp2 = p.d_in2_pad[ori_col * pub.in2_pad_rows + ori_row];

				p.d_in2_sub[col * pub.in2_sub_rows + row] = temp - temp2;

			}
		}

		for(ei_new = 0; ei_new < pub.in2_sub_rows; ei_new++){

			pos_ori = ei_new;

			sum = 0;
			for(position = pos_ori; position < pos_ori + pub.in2_sub_elem; position = position + pub.in2_sub_rows){
				p.d_in2_sub[position] = p.d_in2_sub[position] + sum;
				sum = p.d_in2_sub[position];
			}

		}

		for(col = 0; col < pub.in2_sub2_sqr_cols; col++){
			for(row = 0; row < pub.in2_sub2_sqr_rows; row++){

				ori_row = row + pub.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + pub.in2_sub_cumh_sel_collow - 1;
				temp = p.d_in2_sub[ori_col * pub.in2_sub_rows + ori_row];

				ori_row = row + pub.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + pub.in2_sub_cumh_sel2_collow - 1;
				temp2 = p.d_in2_sub[ori_col * pub.in2_sub_rows + ori_row];

				temp2 = temp - temp2;

				p.d_in2_sub2_sqr[col * pub.in2_sub2_sqr_rows + row] = temp2 * temp2;

				p.d_conv[col * pub.in2_sub2_sqr_rows + row] = p.d_conv[col * pub.in2_sub2_sqr_rows + row] - temp2 * in_final_sum / pub.in_mod_elem;

			}
		}

		for(col = 0; col < pub.in2_pad_cols; col++){
			for(row = 0; row < pub.in2_pad_rows; row++){

				if(	row > (pub.in2_pad_add_rows - 1) &&
					row < (pub.in2_pad_add_rows + pub.in2_rows) &&
					col > (pub.in2_pad_add_cols - 1) &&
					col < (pub.in2_pad_add_cols + pub.in2_cols)){
					ori_row = row - pub.in2_pad_add_rows;
					ori_col = col - pub.in2_pad_add_cols;
					p.d_in2_pad[col * pub.in2_pad_rows + row] = p.d_in2_sqr[ori_col * pub.in2_rows + ori_row];
				}
				else{
					p.d_in2_pad[col * pub.in2_pad_rows + row] = 0;
				}

			}
		}

		for(ei_new = 0; ei_new < pub.in2_pad_cols; ei_new++){

			pos_ori = ei_new * pub.in2_pad_rows;

			sum = 0;
			for(position = pos_ori; position < pos_ori + pub.in2_pad_rows; position = position + 1){
				p.d_in2_pad[position] = p.d_in2_pad[position] + sum;
				sum = p.d_in2_pad[position];
			}

		}

		for(col = 0; col < pub.in2_sub_cols; col++){
			for(row = 0; row < pub.in2_sub_rows; row++){

				ori_row = row + pub.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + pub.in2_pad_cumv_sel_collow - 1;
				temp = p.d_in2_pad[ori_col * pub.in2_pad_rows + ori_row];

				ori_row = row + pub.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + pub.in2_pad_cumv_sel2_collow - 1;
				temp2 = p.d_in2_pad[ori_col * pub.in2_pad_rows + ori_row];

				p.d_in2_sub[col * pub.in2_sub_rows + row] = temp - temp2;

			}
		}

		for(ei_new = 0; ei_new < pub.in2_sub_rows; ei_new++){

			pos_ori = ei_new;

			sum = 0;
			for(position = pos_ori; position < pos_ori + pub.in2_sub_elem; position = position + pub.in2_sub_rows){
				p.d_in2_sub[position] = p.d_in2_sub[position] + sum;
				sum = p.d_in2_sub[position];
			}

		}

		for(col = 0; col < pub.conv_cols; col++){
			for(row = 0; row < pub.conv_rows; row++){

				ori_row = row + pub.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + pub.in2_sub_cumh_sel_collow - 1;
				temp = p.d_in2_sub[ori_col * pub.in2_sub_rows + ori_row];

				ori_row = row + pub.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + pub.in2_sub_cumh_sel2_collow - 1;
				temp2 = p.d_in2_sub[ori_col * pub.in2_sub_rows + ori_row];

				temp2 = temp - temp2;

				temp2 = temp2 - (p.d_in2_sub2_sqr[col * pub.conv_rows + row] / pub.in_mod_elem);

				if(temp2 < 0){
					temp2 = 0;
				}
				temp2 = sqrtf(temp2);

				temp2 = denomT * temp2;

				p.d_conv[col * pub.conv_rows + row] = p.d_conv[col * pub.conv_rows + row] / temp2;

			}
		}

		cent = pub.sSize + pub.tSize + 1;
		pointer = pub.frame_no - 1 + p.point_no * pub.frames;
		tMask_row = cent + p.d_tRowLoc[pointer] - p.d_Row[p.point_no] - 1;
		tMask_col = cent + p.d_tColLoc[pointer] - p.d_Col[p.point_no] - 1;

		for(ei_new = 0; ei_new < pub.tMask_elem; ei_new++){
			p.d_tMask[ei_new] = 0;
		}
		p.d_tMask[tMask_col * pub.tMask_rows + tMask_row] = 1;

		for(col = 1; col <= pub.mask_conv_cols; col++){

			j = col + pub.mask_conv_joffset;
			jp1 = j + 1;
			if(pub.mask_cols < jp1){
				ja1 = jp1 - pub.mask_cols;
			}
			else{
				ja1 = 1;
			}
			if(pub.tMask_cols < j){
				ja2 = pub.tMask_cols;
			}
			else{
				ja2 = j;
			}

			for(row = 1; row <= pub.mask_conv_rows; row++){

				i = row + pub.mask_conv_ioffset;
				ip1 = i + 1;

				if(pub.mask_rows < ip1){
					ia1 = ip1 - pub.mask_rows;
				}
				else{
					ia1 = 1;
				}
				if(pub.tMask_rows < i){
					ia2 = pub.tMask_rows;
				}
				else{
					ia2 = i;
				}

				s = 0;

				for(ja = ja1; ja <= ja2; ja++){
					jb = jp1 - ja;
					for(ia = ia1; ia <= ia2; ia++){
						ib = ip1 - ia;
						(void)jb;
						(void)ib;
						s = s + p.d_tMask[pub.tMask_rows * (ja - 1) + ia - 1] * 1;
					}
				}

				p.d_mask_conv[(col - 1) * pub.conv_rows + (row - 1)] = p.d_conv[(col - 1) * pub.conv_rows + (row - 1)] * s;

			}

		}

		fin_max_val = 0;
		fin_max_coo = 0;
		for(i = 0; i < pub.mask_conv_elem; i++){
			if(p.d_mask_conv[i] > fin_max_val){
				fin_max_val = p.d_mask_conv[i];
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo + 1) % pub.mask_conv_rows - 1;
		largest_col = (fin_max_coo + 1) / pub.mask_conv_rows;
		if((fin_max_coo + 1) % pub.mask_conv_rows == 0){
			largest_row = pub.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - pub.in_mod_rows - (pub.sSize - pub.tSize);
		offset_col = largest_col - pub.in_mod_cols - (pub.sSize - pub.tSize);
		pointer = p.point_no * pub.frames + pub.frame_no;
		p.d_tRowLoc[pointer] = p.d_Row[p.point_no] + offset_row;
		p.d_tColLoc[pointer] = p.d_Col[p.point_no] + offset_col;

	}

	if(pub.frame_no != 0 && (pub.frame_no) % 10 == 0){

		loc_pointer = p.point_no * pub.frames + pub.frame_no;
		p.d_Row[p.point_no] = p.d_tRowLoc[loc_pointer];
		p.d_Col[p.point_no] = p.d_tColLoc[loc_pointer];

		for(col = 0; col < pub.in_mod_cols; col++){
			for(row = 0; row < pub.in_mod_rows; row++){

				ori_row = p.d_Row[p.point_no] - 25 + row - 1;
				ori_col = p.d_Col[p.point_no] - 25 + col - 1;
				ori_pointer = ori_col * pub.frame_rows + ori_row;

				d_in[col * pub.in_mod_rows + row] = pub.alpha * d_in[col * pub.in_mod_rows + row] + (1.00f - pub.alpha) * pub.d_frame[ori_pointer];

			}
		}

	}
}

void write_data(char* filename,
				int frameNo,
				int frames_processed,
				int endoPoints,
				int* input_a,
				int* input_b,
				int epiPoints,
				int* input_2a,
				int* input_2b){

	FILE* fid;
	int i, j;

	fid = fopen(filename, "w+");
	if(fid == NULL){
		printf("The file was not opened for writing\n");
		return;
	}

	fprintf(fid, "Total AVI Frames: %d\n", frameNo);
	fprintf(fid, "Frames Processed: %d\n", frames_processed);
	fprintf(fid, "endoPoints: %d\n", endoPoints);
	fprintf(fid, "epiPoints: %d", epiPoints);
	for(j = 0; j < frames_processed; j++){
		fprintf(fid, "\n---Frame %d---", j);
		fprintf(fid, "\n--endo--\n", j);
		for(i = 0; i < endoPoints; i++){
			fprintf(fid, "%d\t", input_a[j + i * frameNo]);
		}
		fprintf(fid, "\n");
		for(i = 0; i < endoPoints; i++){
			fprintf(fid, "%d\t", input_b[j + i * frameNo]);
		}
		fprintf(fid, "\n--epi--\n", j);
		for(i = 0; i < epiPoints; i++){
			fprintf(fid, "%d\t", input_2a[j + i * frameNo]);
		}
		fprintf(fid, "\n");
		for(i = 0; i < epiPoints; i++){
			fprintf(fid, "%d\t", input_2b[j + i * frameNo]);
		}
	}

	fclose(fid);
}

