		free(host_frame);

		int threads = 64;
		int blocks = (pub.allPoints + threads - 1) / threads;
		kernel_cuda<<<blocks, threads>>>(pub, priv);
		CUDA_CHECK(cudaGetLastError());
		CUDA_CHECK(cudaDeviceSynchronize());

