#include <stdio.h>
#include <stdlib.h>
#include <sys/time.h>
#include <cuda_runtime.h>

long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

using namespace std;

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6)

#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f

#define FACTOR_CHIP 0.5f
#define OPEN

typedef float FLOAT;

const FLOAT t_chip = 0.0005f;
const FLOAT chip_height = 0.016f;
const FLOAT chip_width = 0.016f;
const FLOAT amb_temp = 80.0f;

int num_omp_threads;

static inline void cuda_check(cudaError_t err, const char *msg)
{
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA error: %s: %s\n", msg, cudaGetErrorString(err));
        exit(1);
    }
}

__global__ void single_iteration_kernel(FLOAT *result, const FLOAT *temp, const FLOAT *power,
                                        int row, int col,
                                        FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1)
{
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    int r = blockIdx.y * blockDim.y + threadIdx.y;

    if (r >= row || c >= col) return;

    FLOAT delta;
    int idx = r * col + c;

    if ((r == 0) && (c == 0)) {
        delta = (Cap_1) * (power[0] +
            (temp[1] - temp[0]) * Rx_1 +
            (temp[col] - temp[0]) * Ry_1 +
            (amb_temp - temp[0]) * Rz_1);
    }
    else if ((r == 0) && (c == col - 1)) {
        delta = (Cap_1) * (power[c] +
            (temp[c - 1] - temp[c]) * Rx_1 +
            (temp[c + col] - temp[c]) * Ry_1 +
            (amb_temp - temp[c]) * Rz_1);
    }
    else if ((r == row - 1) && (c == col - 1)) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if ((r == row - 1) && (c == 0)) {
        delta = (Cap_1) * (power[r * col] +
            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
            (temp[(r - 1) * col] - temp[r * col]) * Ry_1 +
            (amb_temp - temp[r * col]) * Rz_1);
    }
    else if (r == 0) {
        delta = (Cap_1) * (power[c] +
            (temp[c + 1] + temp[c - 1] - 2.0f * temp[c]) * Rx_1 +
            (temp[col + c] - temp[c]) * Ry_1 +
            (amb_temp - temp[c]) * Rz_1);
    }
    else if (c == col - 1) {
        delta = (Cap_1) * (power[idx] +
            (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row - 1) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (c == 0) {
        delta = (Cap_1) * (power[r * col] +
            (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[r * col]) * Ry_1 +
            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
            (amb_temp - temp[r * col]) * Rz_1);
    }
    else {
        result[idx] = temp[idx] +
            (Cap_1 * (power[idx] +
            (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1));
        return;
    }

    result[idx] = temp[idx] + delta;
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col)
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0f;

    FLOAT Rx_1 = 1.0f / Rx;
    FLOAT Ry_1 = 1.0f / Ry;
    FLOAT Rz_1 = 1.0f / Rz;
    FLOAT Cap_1 = step / Cap;

    int array_size = row * col;
    size_t bytes = (size_t)array_size * sizeof(FLOAT);

    FLOAT *d_temp0 = NULL;
    FLOAT *d_power = NULL;
    FLOAT *d_result0 = NULL;

    cuda_check(cudaMalloc((void **)&d_temp0, bytes), "cudaMalloc d_temp0");
    cuda_check(cudaMalloc((void **)&d_power, bytes), "cudaMalloc d_power");
    cuda_check(cudaMalloc((void **)&d_result0, bytes), "cudaMalloc d_result0");

    cuda_check(cudaMemcpy(d_temp0, temp, bytes, cudaMemcpyHostToDevice), "cudaMemcpy temp H2D");
    cuda_check(cudaMemcpy(d_power, power, bytes, cudaMemcpyHostToDevice), "cudaMemcpy power H2D");
    cuda_check(cudaMemset(d_result0, 0, bytes), "cudaMemset result");

    FLOAT *d_t = d_temp0;
    FLOAT *d_r = d_result0;

    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((unsigned int)((col + block.x - 1) / block.x),
              (unsigned int)((row + block.y - 1) / block.y));

    for (int i = 0; i < num_iterations; i++) {
        single_iteration_kernel<<<grid, block>>>(d_r, d_t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
        cuda_check(cudaGetLastError(), "kernel launch");
        FLOAT *tmp = d_t;
        d_t = d_r;
        d_r = tmp;
    }

    cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize");

    cuda_check(cudaMemcpy(temp, d_temp0, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy temp D2H");
    cuda_check(cudaMemcpy(result, d_result0, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy result D2H");

    cuda_check(cudaFree(d_temp0), "cudaFree d_temp0");
    cuda_check(cudaFree(d_power), "cudaFree d_power");
    cuda_check(cudaFree(d_result0), "cudaFree d_result0");
}

