using namespace std;

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6)

#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f

#define FACTOR_CHIP 0.5f

typedef float FLOAT;

const FLOAT t_chip = 0.0005f;
const FLOAT chip_height = 0.016f;
const FLOAT chip_width = 0.016f;
const FLOAT amb_temp = 80.0f;

int num_omp_threads;

static inline void cuda_fatal(cudaError_t err, const char *msg)
{
    if (err != cudaSuccess) {
        fprintf(stderr, "error: %s: %s\n", msg, cudaGetErrorString(err));
        exit(1);
    }
}

__global__ void single_iteration_kernel(
    FLOAT *result, const FLOAT *temp, const FLOAT *power,
    int row, int col, FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1)
{
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    int r = blockIdx.y * blockDim.y + threadIdx.y;

    if (r >= row || c >= col)
        return;

    int idx = r * col + c;
    FLOAT delta;

    if ((r == 0) && (c == 0)) {
        delta = (Cap_1) * (power[0] +
            (temp[1] - temp[0]) * Rx_1 +
            (temp[col] - temp[0]) * Ry_1 +
            (amb_temp - temp[0]) * Rz_1);
    }
    else if ((r == 0) && (c == col - 1)) {
        delta = (Cap_1) * (power[c] +
            (temp[c - 1] - temp[c]) * Rx_1 +
            (temp[c + col] - temp[c]) * Ry_1 +
            (amb_temp - temp[c]) * Rz_1);
    }
    else if ((r == row - 1) && (c == col - 1)) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if ((r == row - 1) && (c == 0)) {
        delta = (Cap_1) * (power[r * col] +
            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
            (temp[(r - 1) * col] - temp[r * col]) * Ry_1 +
            (amb_temp - temp[r * col]) * Rz_1);
    }
    else if (r == 0) {
        delta = (Cap_1) * (power[c] +
            (temp[c + 1] + temp[c - 1] - 2.0f * temp[c]) * Rx_1 +
            (temp[col + c] - temp[c]) * Ry_1 +
            (amb_temp - temp[c]) * Rz_1);
    }
    else if (c == col - 1) {
        delta = (Cap_1) * (power[idx] +
            (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row - 1) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (c == 0) {
        delta = (Cap_1) * (power[r * col] +
            (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[r * col]) * Ry_1 +
            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
            (amb_temp - temp[r * col]) * Rz_1);
    }
    else {
        delta = (Cap_1) * (power[idx] +
            (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }

    result[idx] = temp[idx] + delta;
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col)
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0f;

    FLOAT Rx_1 = 1.0f / Rx;
    FLOAT Ry_1 = 1.0f / Ry;
    FLOAT Rz_1 = 1.0f / Rz;
    FLOAT Cap_1 = step / Cap;

    int array_size = row * col;
    size_t bytes = (size_t)array_size * sizeof(FLOAT);

    FLOAT *d_temp = NULL;
    FLOAT *d_power = NULL;
    FLOAT *d_result = NULL;

    cuda_fatal(cudaMalloc((void **)&d_temp, bytes), "unable to allocate device memory for temp");
    cuda_fatal(cudaMalloc((void **)&d_power, bytes), "unable to allocate device memory for power");
    cuda_fatal(cudaMalloc((void **)&d_result, bytes), "unable to allocate device memory for result");

    cuda_fatal(cudaMemcpy(d_temp, temp, bytes, cudaMemcpyHostToDevice), "copy temp to device failed");
    cuda_fatal(cudaMemcpy(d_power, power, bytes, cudaMemcpyHostToDevice), "copy power to device failed");

    FLOAT *t = d_temp;
    FLOAT *r = d_result;

    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((col + block.x - 1) / block.x, (row + block.y - 1) / block.y);

    (void)num_omp_threads;

    for (int i = 0; i < num_iterations; i++) {
        single_iteration_kernel<<<grid, block>>>(r, t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
        cuda_fatal(cudaGetLastError(), "kernel launch failed");
        FLOAT *tmp = t;
        t = r;
        r = tmp;
    }

    if (num_iterations & 1) {
        cuda_fatal(cudaMemcpy(result, d_result, bytes, cudaMemcpyDeviceToHost), "copy result to host failed");
    } else {
        cuda_fatal(cudaMemcpy(temp, d_temp, bytes, cudaMemcpyDeviceToHost), "copy temp to host failed");
    }

    cudaFree(d_temp);
    cudaFree(d_power);
    cudaFree(d_result);
}

