void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col)
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0f;

    FLOAT Rx_1 = 1.0f / Rx;
    FLOAT Ry_1 = 1.0f / Ry;
    FLOAT Rz_1 = 1.0f / Rz;
    FLOAT Cap_1 = step / Cap;

    int array_size = row * col;
    size_t bytes = (size_t)array_size * sizeof(FLOAT);

    FLOAT *d_temp = NULL;
    FLOAT *d_power = NULL;
    FLOAT *d_result = NULL;

    cuda_check(cudaMalloc((void **)&d_temp, bytes), "cudaMalloc d_temp failed");
    cuda_check(cudaMalloc((void **)&d_power, bytes), "cudaMalloc d_power failed");
    cuda_check(cudaMalloc((void **)&d_result, bytes), "cudaMalloc d_result failed");

    cuda_check(cudaMemcpy(d_temp, temp, bytes, cudaMemcpyHostToDevice), "cudaMemcpy temp H2D failed");
    cuda_check(cudaMemcpy(d_power, power, bytes, cudaMemcpyHostToDevice), "cudaMemcpy power H2D failed");
    cuda_check(cudaMemset(d_result, 0, bytes), "cudaMemset d_result failed");

    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((unsigned int)((col + block.x - 1) / block.x),
              (unsigned int)((row + block.y - 1) / block.y));

    FLOAT *d_t = d_temp;
    FLOAT *d_r = d_result;

    for (int i = 0; i < num_iterations; i++) {
        single_iteration_kernel<<<grid, block>>>(d_r, d_t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
        cuda_check(cudaGetLastError(), "kernel launch failed");
        FLOAT *tmp = d_t;
        d_t = d_r;
        d_r = tmp;
    }

    cuda_check(cudaDeviceSynchronize(), "kernel execution failed");
    cuda_check(cudaMemcpy(temp, d_temp, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy temp D2H failed");
    cuda_check(cudaMemcpy(result, d_result, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy result D2H failed");

    cudaFree(d_temp);
    cudaFree(d_power);
    cudaFree(d_result);
}

