static void cuda_fatal_impl(const char *call, cudaError_t err, const char *file, int line)
{
    fprintf(stderr, "Error: CUDA failure at %s:%d: %s: %s\n", file, line, call, cudaGetErrorString(err));
    exit(1);
}

#define CUDA_CHECK(call) \
    do { \
        cudaError_t _err = (call); \
        if (_err != cudaSuccess) cuda_fatal_impl(#call, _err, __FILE__, __LINE__); \
    } while (0)

__global__ static void hotspot3d_kernel(
    const float *pIn,
    const float *tIn,
    float *tOut,
    int nx,
    int ny,
    int nz,
    float cc,
    float cw,
    float ce,
    float cs,
    float cn,
    float cb,
    float ct,
    float stepDivCap,
    float amb_temp)
{
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    int size = nx * ny * nz;
    if (c >= size) return;

    int plane = nx * ny;
    int z = c / plane;
    int rem = c - z * plane;
    int y = rem / nx;
    int x = rem - y * nx;

    int w = (x == 0) ? c : c - 1;
    int e = (x == nx - 1) ? c : c + 1;
    int n = (y == 0) ? c : c - nx;
    int s = (y == ny - 1) ? c : c + nx;
    int b = (z == 0) ? c : c - plane;
    int t = (z == nz - 1) ? c : c + plane;

    tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
            + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t]
            + stepDivCap * pIn[c] + ct * amb_temp;
}

void computeTempOMP(float *pIn, float* tIn, float *tOut,
        int nx, int ny, int nz, float Cap,
        float Rx, float Ry, float Rz,
        float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;

    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int size = nx * ny * nz;
    size_t bytes = (size_t)size * sizeof(float);

    float *d_pIn = NULL;
    float *d_tIn = NULL;
    float *d_tOut = NULL;

    CUDA_CHECK(cudaMalloc((void**)&d_pIn, bytes));
    CUDA_CHECK(cudaMalloc((void**)&d_tIn, bytes));
    CUDA_CHECK(cudaMalloc((void**)&d_tOut, bytes));

    CUDA_CHECK(cudaMemcpy(d_pIn, pIn, bytes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_tIn, tIn, bytes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_tOut, tOut, bytes, cudaMemcpyHostToDevice));

    float *d_tIn_t = d_tIn;
    float *d_tOut_t = d_tOut;

    printf("%d threads running\n", 1);

    int threads = 256;
    int blocks = (size + threads - 1) / threads;

    int count = 0;
    do {
        hotspot3d_kernel<<<blocks, threads>>>(
            d_pIn, d_tIn_t, d_tOut_t,
            nx, ny, nz,
            cc, cw, ce, cs, cn, cb, ct,
            stepDivCap, 80.0f);
        CUDA_CHECK(cudaGetLastError());

        float *t = d_tIn_t;
        d_tIn_t = d_tOut_t;
        d_tOut_t = t;
        count++;
    } while (count < numiter);

    CUDA_CHECK(cudaMemcpy(tIn, d_tIn, bytes, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(tOut, d_tOut, bytes, cudaMemcpyDeviceToHost));

    CUDA_CHECK(cudaFree(d_pIn));
    CUDA_CHECK(cudaFree(d_tIn));
    CUDA_CHECK(cudaFree(d_tOut));
}

