			printf("Cuda error: %s: %s.\n", #call, cudaGetErrorString(err__));  \
			fflush(NULL);                                                        \
			exit(EXIT_FAILURE);                                                  \
		}                                                                       \
	} while (0)

__global__ void kernel_gpu_cuda(par_str par,
								dim_str dim,
								const box_str* box,
								const FOUR_VECTOR* rv,
								const fp* qv,
								FOUR_VECTOR* fv)
{
	int l = blockIdx.x;
	int i = threadIdx.x;

	if ((long)l < dim.number_boxes && i < NUMBER_PAR_PER_BOX) {
		long first_i = box[l].offset;
		const FOUR_VECTOR* rA = &rv[first_i];
		FOUR_VECTOR f = fv[first_i + i];
		FOUR_VECTOR rAi = rA[i];

		fp a2 = 2.0 * par.alpha * par.alpha;

		for (int k = 0; k < (1 + box[l].nn); k++) {
			int pointer;
			if (k == 0) {
				pointer = l;
			}
			else {
				pointer = box[l].nei[k - 1].number;
			}

			long first_j = box[pointer].offset;
			const FOUR_VECTOR* rB = &rv[first_j];
			const fp* qB = &qv[first_j];

			for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
				fp r2 = rAi.v + rB[j].v - DOT(rAi, rB[j]);
				fp u2 = a2 * r2;
				fp vij = exp(-u2);
				fp fs = 2.0 * vij;
				THREE_VECTOR d;
				d.x = rAi.x - rB[j].x;
				d.y = rAi.y - rB[j].y;
				d.z = rAi.z - rB[j].z;
