				fp fyij = fs * d.y;
				fp fzij = fs * d.z;

				f.v += qB[j] * vij;
				f.x += qB[j] * fxij;
				f.y += qB[j] * fyij;
				f.z += qB[j] * fzij;
			}
		}

		fv[first_i + i] = f;
	}
