__global__ void kernel_gpu_cuda(box_str* box,
                                FOUR_VECTOR* rv,
                                fp* qv,
                                FOUR_VECTOR* fv,
                                fp a2,
                                long number_boxes)
{
    for (long l = (long)blockIdx.x; l < number_boxes; l += (long)gridDim.x) {
        long first_i = box[l].offset;

        for (int i = threadIdx.x; i < NUMBER_PAR_PER_BOX; i += blockDim.x) {
            FOUR_VECTOR rA_i = rv[first_i + i];
            FOUR_VECTOR fA_i = fv[first_i + i];

            for (int k = 0; k < (1 + box[l].nn); k++) {
                int pointer;
                if (k == 0) {
                    pointer = (int)l;
                } else {
                    pointer = box[l].nei[k - 1].number;
                }

                long first_j = box[pointer].offset;
                FOUR_VECTOR* rB = &rv[first_j];
                fp* qB = &qv[first_j];

                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    fp r2 = rA_i.v + rB[j].v - DOT(rA_i, rB[j]);
                    fp u2 = a2 * r2;
                    fp vij = exp(-u2);
                    fp fs = 2.0 * vij;

                    fp dx = rA_i.x - rB[j].x;
                    fp dy = rA_i.y - rB[j].y;
                    fp dz = rA_i.z - rB[j].z;

                    fp fxij = fs * dx;
                    fp fyij = fs * dy;
                    fp fzij = fs * dz;

                    fA_i.v += qB[j] * vij;
                    fA_i.x += qB[j] * fxij;
                    fA_i.y += qB[j] * fyij;
                    fA_i.z += qB[j] * fzij;
                }
            }

            fv[first_i + i] = fA_i;
        }
    }
}

