{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;

    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

#ifdef __cplusplus
extern "C" {
#endif
long long get_time();
void setdevice(void);
void checkCUDAError(const char *msg);
#ifdef __cplusplus
}
#endif

__global__ void kernel_gpu_cuda(box_str* box,
                                FOUR_VECTOR* rv,
                                fp* qv,
                                FOUR_VECTOR* fv,
                                fp a2,
                                long number_boxes)
{
    long l = (long)blockIdx.x;
    int i = threadIdx.x;

    if (l >= number_boxes || i >= NUMBER_PAR_PER_BOX) {
        return;
    }

    long first_i = box[l].offset;
    FOUR_VECTOR rAi = rv[first_i + i];
    FOUR_VECTOR fAi = fv[first_i + i];

    for (int k = 0; k < (1 + box[l].nn); k++) {

        int pointer;
        if (k == 0) {
            pointer = (int)l;
        } else {
            pointer = box[l].nei[k - 1].number;
        }

        long first_j = box[pointer].offset;

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {

            FOUR_VECTOR rBj = rv[first_j + j];
            fp qBj = qv[first_j + j];

            fp r2 = rAi.v + rBj.v - DOT(rAi, rBj);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;

            THREE_VECTOR d;
            d.x = rAi.x - rBj.x;
            d.y = rAi.y - rBj.y;
            d.z = rAi.z - rBj.z;

            fp fxij = fs * d.x;
            fp fyij = fs * d.y;
            fp fzij = fs * d.z;

            fAi.v += qBj * vij;
            fAi.x += qBj * fxij;
            fAi.y += qBj * fyij;
            fAi.z += qBj * fzij;
        }
    }

    fv[first_i + i] = fAi;
}

