#include <stdio.h>
#include <cuda_runtime.h>

#define BS 16

static void lud_base_host(float *a, int size) {
    int i, j, k;
    float sum;

    for (i = 0; i < size; i++) {
        for (j = i; j < size; j++) {
            sum = a[(size_t)i * size + j];
            for (k = 0; k < i; k++) {
                sum -= a[(size_t)i * size + k] * a[(size_t)k * size + j];
            }
            a[(size_t)i * size + j] = sum;
        }

        for (j = i + 1; j < size; j++) {
            sum = a[(size_t)j * size + i];
            for (k = 0; k < i; k++) {
                sum -= a[(size_t)j * size + k] * a[(size_t)k * size + i];
            }
            a[(size_t)j * size + i] = sum / a[(size_t)i * size + i];
        }
    }
}

__global__ static void lud_diagonal_kernel(float *a, int size, int offset) {
    if (blockIdx.x != 0 || threadIdx.x != 0) return;

    for (int i = 0; i < BS; i++) {
        for (int j = i; j < BS; j++) {
            for (int k = 0; k < i; k++) {
                a[(size_t)(offset + i) * size + (offset + j)] -=
                    a[(size_t)(offset + i) * size + (offset + k)] *
                    a[(size_t)(offset + k) * size + (offset + j)];
            }
        }

        float temp = 1.0f / a[(size_t)(offset + i) * size + (offset + i)];
        for (int j = i + 1; j < BS; j++) {
            for (int k = 0; k < i; k++) {
                a[(size_t)(offset + j) * size + (offset + i)] -=
                    a[(size_t)(offset + j) * size + (offset + k)] *
                    a[(size_t)(offset + k) * size + (offset + i)];
            }
            a[(size_t)(offset + j) * size + (offset + i)] *= temp;
        }
    }
}

__global__ static void lud_perimeter_top_kernel(float *a, int size, int offset) {
    __shared__ float temp[BS * BS];
    int j = threadIdx.x;
    int chunk_idx = blockIdx.x;
    int j_global = offset + BS * (chunk_idx + 1);

    for (int i = 0; i < BS; i++) {
        temp[i * BS + j] = a[(size_t)(offset + i) * size + (offset + j)];
    }
    __syncthreads();

    for (int i = 0; i < BS; i++) {
        float sum = 0.0f;
        for (int k = 0; k < i; k++) {
            sum += temp[i * BS + k] * a[(size_t)(offset + k) * size + (j_global + j)];
        }
        a[(size_t)(offset + i) * size + (j_global + j)] -= sum;
    }
}

__global__ static void lud_perimeter_left_kernel(float *a, int size, int offset) {
    __shared__ float temp[BS * BS];
    int i = threadIdx.x;
    int chunk_idx = blockIdx.x;
    int i_global = offset + BS * (chunk_idx + 1);

    for (int j = 0; j < BS; j++) {
        temp[i * BS + j] = a[(size_t)(offset + i) * size + (offset + j)];
    }
    __syncthreads();

    for (int j = 0; j < BS; j++) {
        float sum = 0.0f;
        for (int k = 0; k < j; k++) {
            sum += a[(size_t)(i_global + i) * size + (offset + k)] * temp[k * BS + j];
        }
        a[(size_t)(i_global + i) * size + (offset + j)] =
            (a[(size_t)(i_global + i) * size + (offset + j)] - sum) /
            a[(size_t)(offset + j) * size + (offset + j)];
    }
}

__global__ static void lud_internal_kernel(float *a, int size, int offset) {
    __shared__ float temp_top[BS * BS];
    __shared__ float temp_left[BS * BS];

    int j = threadIdx.x;
    int i = threadIdx.y;

    int block_i = blockIdx.y;
    int block_j = blockIdx.x;

    int i_global = offset + BS * (1 + block_i);
    int j_global = offset + BS * (1 + block_j);

    temp_top[i * BS + j] = a[(size_t)(offset + i) * size + (j_global + j)];
    temp_left[i * BS + j] = a[(size_t)(i_global + i) * size + (offset + j)];
    __syncthreads();

    float sum = 0.0f;
    for (int k = 0; k < BS; k++) {
        sum += temp_left[i * BS + k] * temp_top[k * BS + j];
    }

    a[(size_t)(i_global + i) * size + (j_global + j)] -= sum;
}

static bool lud_cuda(float *a_host, int size) {
    if (size < BS || (size % BS) != 0) return false;

    int device_count = 0;
    cudaError_t err = cudaGetDeviceCount(&device_count);
    if (err != cudaSuccess || device_count <= 0) return false;

    float *d_a = NULL;
    size_t bytes = (size_t)size * size * sizeof(float);

    err = cudaMalloc((void **)&d_a, bytes);
    if (err != cudaSuccess) return false;

    err = cudaMemcpy(d_a, a_host, bytes, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        cudaFree(d_a);
        return false;
    }

    int offset = 0;
    for (offset = 0; offset < size - BS; offset += BS) {
        lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            cudaFree(d_a);
            return false;
        }
        err = cudaDeviceSynchronize();
        if (err != cudaSuccess) {
            cudaFree(d_a);
            return false;
        }

        int size_inter = size - offset - BS;
        int chunks_in_inter_row = size_inter / BS;

        if (chunks_in_inter_row > 0) {
            lud_perimeter_top_kernel<<<chunks_in_inter_row, BS>>>(d_a, size, offset);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                cudaFree(d_a);
                return false;
            }

            lud_perimeter_left_kernel<<<chunks_in_inter_row, BS>>>(d_a, size, offset);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                cudaFree(d_a);
                return false;
            }

            err = cudaDeviceSynchronize();
            if (err != cudaSuccess) {
                cudaFree(d_a);
                return false;
            }

            dim3 grid((unsigned int)chunks_in_inter_row, (unsigned int)chunks_in_inter_row);
            dim3 block(BS, BS);
            lud_internal_kernel<<<grid, block>>>(d_a, size, offset);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                cudaFree(d_a);
                return false;
            }

            err = cudaDeviceSynchronize();
            if (err != cudaSuccess) {
                cudaFree(d_a);
                return false;
            }
        }
    }

    lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);
    err = cudaGetLastError();
