#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#define BS 16

static void lud_base_cpu(float *a, int size)
{
    int i, j, k;
    float sum;

    for (i = 0; i < size; i++) {
        for (j = i; j < size; j++) {
            sum = a[i * size + j];
            for (k = 0; k < i; k++)
                sum -= a[i * size + k] * a[k * size + j];
            a[i * size + j] = sum;
        }

        for (j = i + 1; j < size; j++) {
            sum = a[j * size + i];
            for (k = 0; k < i; k++)
                sum -= a[j * size + k] * a[k * size + i];
            a[j * size + i] = sum / a[i * size + i];
        }
    }
}

__global__ static void lud_diagonal_kernel(float *a, int size, int offset)
{
    if (threadIdx.x != 0 || blockIdx.x != 0)
        return;

    for (int i = 0; i < BS; i++) {
        for (int j = i; j < BS; j++) {
            for (int k = 0; k < i; k++) {
                a[(offset + i) * size + (offset + j)] =
                    a[(offset + i) * size + (offset + j)] -
                    a[(offset + i) * size + (offset + k)] *
                    a[(offset + k) * size + (offset + j)];
            }
        }

        float temp = 1.0f / a[(offset + i) * size + (offset + i)];
        for (int j = i + 1; j < BS; j++) {
            for (int k = 0; k < i; k++) {
                a[(offset + j) * size + (offset + i)] =
                    a[(offset + j) * size + (offset + i)] -
                    a[(offset + j) * size + (offset + k)] *
                    a[(offset + k) * size + (offset + i)];
            }
            a[(offset + j) * size + (offset + i)] =
                a[(offset + j) * size + (offset + i)] * temp;
        }
    }
}

__global__ static void lud_perimeter_kernel(float *a, int size, int offset)
{
    int tid = threadIdx.x;
    int chunk_idx = blockIdx.x;

    __shared__ float temp[BS * BS];

    for (int idx = tid; idx < BS * BS; idx += blockDim.x) {
        int i = idx / BS;
        int j = idx % BS;
        temp[idx] = a[(offset + i) * size + (offset + j)];
    }
    __syncthreads();

    if (tid < BS) {
        int j = tid;
        int i_global = offset;
        int j_global = offset + BS * (chunk_idx + 1);

        for (int i = 0; i < BS; i++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += temp[BS * i + k] * a[(i_global + k) * size + (j_global + j)];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            a[i_here * size + j_here] = a[i_here * size + j_here] - sum;
        }
    }

    __syncthreads();

    if (tid < BS) {
        int i = tid;
        int j_global = offset;
        int i_global = offset + BS * (chunk_idx + 1);

        for (int j = 0; j < BS; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += a[(i_global + i) * size + (j_global + k)] * temp[BS * k + j];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            a[i_here * size + j_here] =
                (a[i_here * size + j_here] - sum) /
                a[(offset + j) * size + (offset + j)];
        }
    }
}

__global__ static void lud_internal_kernel(float *a, int size, int offset)
{
    int j = threadIdx.x;
    int i = threadIdx.y;

    int chunk_j = blockIdx.x;
    int chunk_i = blockIdx.y;

    int i_global = offset + BS * (1 + chunk_i);
    int j_global = offset + BS * (1 + chunk_j);

    __shared__ float temp_top[BS * BS];
    __shared__ float temp_left[BS * BS];

    temp_top[i * BS + j]  = a[(offset + i) * size + (j_global + j)];
    temp_left[i * BS + j] = a[(i_global + i) * size + (offset + j)];
    __syncthreads();

    float sum = 0.0f;
    for (int k = 0; k < BS; k++) {
        sum += temp_left[i * BS + k] * temp_top[k * BS + j];
    }

    a[(i_global + i) * size + (j_global + j)] -= sum;
}

extern "C" void lud_omp(float *a, int size)
{
    if (a == NULL || size <= 0)
        return;

    printf("running OMP on host\n");

    if (size < BS || (size % BS) != 0) {
        lud_base_cpu(a, size);
        return;
    }

    int device_count = 0;
    if (cudaGetDeviceCount(&device_count) != cudaSuccess || device_count <= 0) {
        cudaGetLastError();
        lud_base_cpu(a, size);
        return;
    }

    float *d_a = NULL;
    size_t bytes = (size_t)size * (size_t)size * sizeof(float);

    if (cudaMalloc((void**)&d_a, bytes) != cudaSuccess) {
        if (d_a) cudaFree(d_a);
        cudaGetLastError();
        lud_base_cpu(a, size);
        return;
    }

    if (cudaMemcpy(d_a, a, bytes, cudaMemcpyHostToDevice) != cudaSuccess) {
        cudaFree(d_a);
        cudaGetLastError();
        lud_base_cpu(a, size);
        return;
    }

    int offset;
    for (offset = 0; offset < size - BS; offset += BS) {
        lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);

        int chunks_in_inter_row = (size - offset - BS) / BS;
        if (chunks_in_inter_row > 0) {
            lud_perimeter_kernel<<<chunks_in_inter_row, BS>>>(d_a, size, offset);

            dim3 grid((unsigned int)chunks_in_inter_row, (unsigned int)chunks_in_inter_row, 1);
            dim3 block(BS, BS, 1);
            lud_internal_kernel<<<grid, block>>>(d_a, size, offset);
        }
    }

    lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);

    if (cudaDeviceSynchronize() != cudaSuccess) {
        cudaFree(d_a);
        cudaGetLastError();
        lud_base_cpu(a, size);
        return;
    }

    if (cudaMemcpy(a, d_a, bytes, cudaMemcpyDeviceToHost) != cudaSuccess) {
        cudaFree(d_a);
        cudaGetLastError();
        lud_base_cpu(a, size);
        return;
    }

    cudaFree(d_a);
}

