static void lud_base_host(float *a, int size) {
    int i, j, k;
    float sum;

    for (i = 0; i < size; i++) {
        for (j = i; j < size; j++) {
            sum = a[i * size + j];
            for (k = 0; k < i; k++)
                sum -= a[i * size + k] * a[k * size + j];
            a[i * size + j] = sum;
        }

        for (j = i + 1; j < size; j++) {
            sum = a[j * size + i];
            for (k = 0; k < i; k++)
                sum -= a[j * size + k] * a[k * size + i];
            a[j * size + i] = sum / a[i * size + i];
        }
    }
}

__global__ static void lud_diagonal_kernel(float *a, int size, int offset) {
    if (blockIdx.x != 0 || threadIdx.x != 0)
        return;

    for (int i = 0; i < BS; i++) {
        for (int j = i; j < BS; j++) {
            for (int k = 0; k < i; k++) {
                a[(offset + i) * size + (offset + j)] =
                    a[(offset + i) * size + (offset + j)] -
                    a[(offset + i) * size + (offset + k)] *
                        a[(offset + k) * size + (offset + j)];
            }
        }

        float temp = 1.f / a[(offset + i) * size + (offset + i)];
        for (int j = i + 1; j < BS; j++) {
            for (int k = 0; k < i; k++) {
                a[(offset + j) * size + (offset + i)] =
                    a[(offset + j) * size + (offset + i)] -
                    a[(offset + j) * size + (offset + k)] *
                        a[(offset + k) * size + (offset + i)];
            }
            a[(offset + j) * size + (offset + i)] =
                a[(offset + j) * size + (offset + i)] * temp;
        }
    }
}

__global__ static void lud_perimeter_kernel(float *a, int size, int offset, int chunks_in_inter_row) {
    int chunk_idx = blockIdx.x;
    if (threadIdx.x != 0 || chunk_idx >= chunks_in_inter_row)
        return;

    int i, j, k, i_global, j_global, i_here, j_here;
    float sum;
    float temp[BS * BS];

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp[i * BS + j] = a[size * (i + offset) + offset + j];
        }
    }

    i_global = offset;
    j_global = offset;
    j_global += BS * (chunk_idx + 1);

    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp[BS * i + k] * a[(i_global + k) * size + (j_global + j)];
            }
            i_here = i_global + i;
            j_here = j_global + j;
            a[i_here * size + j_here] = a[i_here * size + j_here] - sum;
        }
    }

    j_global = offset;
    i_global += BS * (chunk_idx + 1);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += a[(i_global + i) * size + (j_global + k)] * temp[BS * k + j];
            }
            i_here = i_global + i;
            j_here = j_global + j;
            a[i_here * size + j_here] =
                (a[i_here * size + j_here] - sum) / a[(offset + j) * size + (offset + j)];
        }
    }
}

__global__ static void lud_internal_kernel(float *a, int size, int offset, int chunks_in_inter_row) {
    int chunk_idx = blockIdx.x;
    if (threadIdx.x != 0)
        return;

    int chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
    if (chunk_idx >= chunks_per_inter)
        return;

    int i, j, k, i_global, j_global;
    float temp_top[BS * BS];
    float temp_left[BS * BS];

    i_global = offset + BS * (1 + chunk_idx / chunks_in_inter_row);
    j_global = offset + BS * (1 + chunk_idx % chunks_in_inter_row);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_top[i * BS + j] = a[size * (i + offset) + j + j_global];
            temp_left[i * BS + j] = a[size * (i + i_global) + offset + j];
        }
    }

    for (i = 0; i < BS; i++) {
        float sum[BS];
        for (j = 0; j < BS; j++)
            sum[j] = 0.f;

        for (k = 0; k < BS; k++) {
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left[BS * i + k] * temp_top[BS * k + j];
            }
        }

        for (j = 0; j < BS; j++) {
            a[(i + i_global) * size + (j + j_global)] -= sum[j];
        }
    }
}

void lud_omp(float *a, int size) {
    int offset, size_inter, chunks_in_inter_row, chunks_per_inter;
    float *d_a = NULL;
    size_t bytes;

    printf("running OMP on host\n");
    (void)omp_num_threads;

    if (size <= 0)
        return;

    if (size < BS || (size % BS) != 0) {
        lud_base_host(a, size);
        return;
    }

    bytes = (size_t)size * (size_t)size * sizeof(float);

    CUDA_CHECK(cudaMalloc((void **)&d_a, bytes));
    CUDA_CHECK(cudaMemcpy(d_a, a, bytes, cudaMemcpyHostToDevice));

    for (offset = 0; offset < size - BS; offset += BS) {
        lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);
        CUDA_CHECK(cudaGetLastError());

        size_inter = size - offset - BS;
        chunks_in_inter_row = size_inter / BS;

        if (chunks_in_inter_row > 0) {
            lud_perimeter_kernel<<<chunks_in_inter_row, 1>>>(d_a, size, offset, chunks_in_inter_row);
            CUDA_CHECK(cudaGetLastError());

            chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
            lud_internal_kernel<<<chunks_per_inter, 1>>>(d_a, size, offset, chunks_in_inter_row);
            CUDA_CHECK(cudaGetLastError());
        }
    }

    lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    CUDA_CHECK(cudaMemcpy(a, d_a, bytes, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaFree(d_a));
}

