	finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(initvalu_32-initvalu_33)+J_na_slmyo*oneovervsl*(initvalu_34-initvalu_33)-finavalu[offset_18];
	finavalu[offset_34] = J_na_slmyo/Vmyo*(initvalu_33-initvalu_34);

	I_K_tot = I_to+I_kr+I_ks+I_ki-2.0f*I_nak+I_CaK+I_kp;
	finavalu[offset_35] = 0.0f;

	I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2.0f*I_ncx_junc;
	I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2.0f*I_ncx_sl;
	finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2.0f*Frdy)+J_ca_juncsl/Vjunc*(initvalu_37-initvalu_36)
	         - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
	finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2.0f*Frdy)+J_ca_juncsl/Vsl*(initvalu_36-initvalu_37)
	         + J_ca_slmyo/Vsl*(initvalu_38-initvalu_37)-J_CaB_sl;
	finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(initvalu_37-initvalu_38);
	junc_sl=J_ca_juncsl/Vsl*(initvalu_36-initvalu_37);
	sl_junc=J_ca_juncsl/Vjunc*(initvalu_37-initvalu_36);
	sl_myo=J_ca_slmyo/Vsl*(initvalu_38-initvalu_37);
	myo_sl=J_ca_slmyo/Vmyo*(initvalu_37-initvalu_38);

	state = 1;
	switch(state){
		case 0:
			I_app = 0.0f;
			break;
		case 1:
			if(fmodf(timeinst,parameter_1) <= 5.0f){
				I_app = 9.5f;
			}
			else{
				I_app = 0.0f;
			}
			break;
		case 2:
			V_hold = -55.0f;
			V_test = 0.0f;
			if(timeinst>0.5f & timeinst<200.5f){
				V_clamp = V_test;
			}
			else{
				V_clamp = V_hold;
			}
			R_clamp = 0.04f;
			I_app = (V_clamp-initvalu_39)/R_clamp;
			break;
	}

	I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
	I_Cl_tot = I_ClCa+I_Clbk;
	I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
	I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
	finavalu[offset_39] = -(I_tot-I_app);

	finavalu[offset_41] = 0.0f;
	finavalu[offset_42] = 0.0f;
}

__device__ void kernel_cam_2(fp timeinst,
                             fp *initvalu,
                             fp *finavalu,
                             int initvalu_offset,
                             fp *parameter,
                             int parameter_offset,
                             fp *com,
                             int com_offset,
                             fp Ca) {

	fp JCa;

	int offset_1;
	int offset_2;
	int offset_3;
	int offset_4;
	int offset_5;
	int offset_6;
	int offset_7;
	int offset_8;
	int offset_9;
	int offset_10;
	int offset_11;
	int offset_12;
	int offset_13;
	int offset_14;
	int offset_15;

	int parameter_offset_1;
	int parameter_offset_2;
	int parameter_offset_3;
	int parameter_offset_4;
	int parameter_offset_5;

	fp CaM;
	fp Ca2CaM;
	fp Ca4CaM;
	fp CaMB;
	fp Ca2CaMB;
	fp Ca4CaMB;
	fp Pb2;
	fp Pb;
	fp Pt;
	fp Pt2;
	fp Pa;
	fp Ca4CaN;
	fp CaMCa4CaN;
	fp Ca2CaMCa4CaN;
	fp Ca4CaMCa4CaN;

	fp CaMtot;
	fp Btot;
	fp CaMKIItot;
	fp CaNtot;
	fp PP1tot;

	fp K;
	fp Mg;

	fp Kd02;
	fp Kd24;
	fp k20;
	fp k02;
	fp k42;
	fp k24;

	fp k0Boff;
	fp k0Bon;
	fp k2Boff;
	fp k2Bon;
	fp k4Boff;
	fp k4Bon;

	fp k20B;
	fp k02B;
	fp k42B;
	fp k24B;

	fp kbi;
	fp kib;
	fp kpp1;
	fp Kmpp1;
	fp kib2;
	fp kb2i;
	fp kb24;
	fp kb42;
	fp kta;
	fp kat;
	fp kt42;
	fp kt24;
	fp kat2;
	fp kt2a;

	fp kcanCaoff;
	fp kcanCaon;
	fp kcanCaM4on;
	fp kcanCaM4off;
	fp kcanCaM2on;
	fp kcanCaM2off;
	fp kcanCaM0on;
	fp kcanCaM0off;
	fp k02can;
	fp k20can;
	fp k24can;
	fp k42can;

	fp rcn02;
	fp rcn24;

	fp B;
	fp rcn02B;
	fp rcn24B;
	fp rcn0B;
	fp rcn2B;
	fp rcn4B;

	fp Ca2CaN;
	fp rcnCa4CaN;
	fp rcn02CaN;
	fp rcn24CaN;
	fp rcn0CaN;
	fp rcn2CaN;
	fp rcn4CaN;

	fp Pix;
	fp rcnCKib2;
	fp rcnCKb2b;
	fp rcnCKib;
	fp T;
	fp kbt;
	fp rcnCKbt;
	fp rcnCKtt2;
	fp rcnCKta;
	fp rcnCKt2a;
	fp rcnCKt2b2;
	fp rcnCKai;

	fp dCaM;
	fp dCa2CaM;
	fp dCa4CaM;
	fp dCaMB;
	fp dCa2CaMB;
	fp dCa4CaMB;

	fp dPb2;
	fp dPb;
	fp dPt;
	fp dPt2;
	fp dPa;

	fp dCa4CaN;
	fp dCaMCa4CaN;
	fp dCa2CaMCa4CaN;
	fp dCa4CaMCa4CaN;

	offset_1  = initvalu_offset;
	offset_2  = initvalu_offset+1;
	offset_3  = initvalu_offset+2;
	offset_4  = initvalu_offset+3;
	offset_5  = initvalu_offset+4;
	offset_6  = initvalu_offset+5;
	offset_7  = initvalu_offset+6;
	offset_8  = initvalu_offset+7;
	offset_9  = initvalu_offset+8;
	offset_10 = initvalu_offset+9;
	offset_11 = initvalu_offset+10;
	offset_12 = initvalu_offset+11;
	offset_13 = initvalu_offset+12;
	offset_14 = initvalu_offset+13;
	offset_15 = initvalu_offset+14;

	parameter_offset_1  = parameter_offset+1;
	parameter_offset_2  = parameter_offset+2;
	parameter_offset_3  = parameter_offset+3;
	parameter_offset_4  = parameter_offset+4;
	parameter_offset_5  = parameter_offset+5;

	CaM				= initvalu[offset_1];
	Ca2CaM			= initvalu[offset_2];
	Ca4CaM			= initvalu[offset_3];
	CaMB			= initvalu[offset_4];
	Ca2CaMB			= initvalu[offset_5];
	Ca4CaMB			= initvalu[offset_6];
	Pb2				= initvalu[offset_7];
	Pb				= initvalu[offset_8];
	Pt				= initvalu[offset_9];
	Pt2				= initvalu[offset_10];
	Pa				= initvalu[offset_11];
	Ca4CaN			= initvalu[offset_12];
	CaMCa4CaN		= initvalu[offset_13];
	Ca2CaMCa4CaN	= initvalu[offset_14];
	Ca4CaMCa4CaN	= initvalu[offset_15];

	CaMtot			= parameter[parameter_offset_1];
	Btot			= parameter[parameter_offset_2];
	CaMKIItot		= parameter[parameter_offset_3];
	CaNtot			= parameter[parameter_offset_4];
	PP1tot			= parameter[parameter_offset_5];

	K = 135.0f;
	Mg = 1.0f;

	if (Mg <= 1.0f){
		Kd02 = 0.0025f*(1.0f+K/0.94f-Mg/0.012f)*(1.0f+K/8.1f+Mg/0.022f);
		Kd24 = 0.128f*(1.0f+K/0.64f+Mg/0.0014f)*(1.0f+K/13.0f-Mg/0.153f);
	}
	else{
		Kd02 = 0.0025f*(1.0f+K/0.94f-1.0f/0.012f+(Mg-1.0f)/0.060f)*(1.0f+K/8.1f+1.0f/0.022f+(Mg-1.0f)/0.068f);
		Kd24 = 0.128f*(1.0f+K/0.64f+1.0f/0.0014f+(Mg-1.0f)/0.005f)*(1.0f+K/13.0f-1.0f/0.153f+(Mg-1.0f)/0.150f);
	}
	k20 = 10.0f;
	k02 = k20/Kd02;
	k42 = 500.0f;
	k24 = k42/Kd24;

	k0Boff = 0.0014f;
	k0Bon = k0Boff/0.2f;
	k2Boff = k0Boff/100.0f;
	k2Bon = k0Bon;
	k4Boff = k2Boff;
	k4Bon = k0Bon;

	k20B = k20/100.0f;
	k02B = k02;
	k42B = k42;
	k24B = k24;

	kbi = 2.2f;
	kib = kbi/33.5e-3f;
	kpp1 = 1.72f;
	Kmpp1 = 11.5f;
	kib2 = kib;
	kb2i = kib2*5.0f;
	kb24 = k24;
	kb42 = k42*33.5e-3f/5.0f;
	kta = kbi/1000.0f;
	kat = kib;
	kt42 = k42*33.5e-6f/5.0f;
	kt24 = k24;
	kat2 = kib;
	kt2a = kib*5.0f;

	kcanCaoff = 1.0f;
	kcanCaon = kcanCaoff/0.5f;
	kcanCaM4on = 46.0f;
	kcanCaM4off = 0.0013f;
	kcanCaM2on = kcanCaM4on;
	kcanCaM2off = 2508.0f*kcanCaM4off;
	kcanCaM0on = kcanCaM4on;
	kcanCaM0off = 165.0f*kcanCaM2off;
	k02can = k02;
	k20can = k20/165.0f;
	k24can = k24;
	k42can = k20/2508.0f;

	rcn02 = k02*powf(Ca,2.0f)*CaM - k20*Ca2CaM;
	rcn24 = k24*powf(Ca,2.0f)*Ca2CaM - k42*Ca4CaM;

	B = Btot - CaMB - Ca2CaMB - Ca4CaMB;
	rcn02B = k02B*powf(Ca,2.0f)*CaMB - k20B*Ca2CaMB;
	rcn24B = k24B*powf(Ca,2.0f)*Ca2CaMB - k42B*Ca4CaMB;
	rcn0B = k0Bon*CaM*B - k0Boff*CaMB;
	rcn2B = k2Bon*Ca2CaM*B - k2Boff*Ca2CaMB;
	rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;

	Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
	rcnCa4CaN = kcanCaon*powf(Ca,2.0f)*Ca2CaN - kcanCaoff*Ca4CaN;
	rcn02CaN = k02can*powf(Ca,2.0f)*CaMCa4CaN - k20can*Ca2CaMCa4CaN;
	rcn24CaN = k24can*powf(Ca,2.0f)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
	rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN;
	rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN;
	rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;

	Pix = 1.0f - Pb2 - Pb - Pt - Pt2 - Pa;
	rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2;
	rcnCKb2b = kb24*powf(Ca,2.0f)*Pb2 - kb42*Pb;
	rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
	T = Pb + Pt + Pt2 + Pa;
	kbt = 0.055f*T + 0.0074f*powf(T,2.0f) + 0.015f*powf(T,3.0f);
	rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
	rcnCKtt2 = kt42*Pt - kt24*powf(Ca,2.0f)*Pt2;
	rcnCKta = kta*Pt - kat*Ca4CaM*Pa;
	rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
	rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2);
	rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);

	dCaM = 1e-3f*(-rcn02 - rcn0B - rcn0CaN);
	dCa2CaM = 1e-3f*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a) );
	dCa4CaM = 1e-3f*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib+rcnCKta) );
	dCaMB = 1e-3f*(rcn0B-rcn02B);
	dCa2CaMB = 1e-3f*(rcn02B + rcn2B - rcn24B);
	dCa4CaMB = 1e-3f*(rcn24B + rcn4B);

	dPb2 = 1e-3f*(rcnCKib2 - rcnCKb2b + rcnCKt2b2);
	dPb = 1e-3f*(rcnCKib + rcnCKb2b - rcnCKbt);
	dPt = 1e-3f*(rcnCKbt-rcnCKta-rcnCKtt2);
	dPt2 = 1e-3f*(rcnCKtt2-rcnCKt2a-rcnCKt2b2);
	dPa = 1e-3f*(rcnCKta+rcnCKt2a-rcnCKai);

	dCa4CaN = 1e-3f*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN);
	dCaMCa4CaN = 1e-3f*(rcn0CaN - rcn02CaN);
	dCa2CaMCa4CaN = 1e-3f*(rcn2CaN+rcn02CaN-rcn24CaN);
	dCa4CaMCa4CaN = 1e-3f*(rcn4CaN+rcn24CaN);

	finavalu[offset_1] = dCaM;
	finavalu[offset_2] = dCa2CaM;
	finavalu[offset_3] = dCa4CaM;
	finavalu[offset_4] = dCaMB;
	finavalu[offset_5] = dCa2CaMB;
	finavalu[offset_6] = dCa4CaMB;
	finavalu[offset_7] = dPb2;
	finavalu[offset_8] = dPb;
	finavalu[offset_9] = dPt;
	finavalu[offset_10] = dPt2;
	finavalu[offset_11] = dPa;
	finavalu[offset_12] = dCa4CaN;
	finavalu[offset_13] = dCaMCa4CaN;
	finavalu[offset_14] = dCa2CaMCa4CaN;
	finavalu[offset_15] = dCa4CaMCa4CaN;

	JCa = 1e-3f*(2.0f*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2.0f*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));

	com[com_offset] = JCa;
}

void kernel_fin(fp *initvalu,
                int initvalu_offset_ecc,
                int initvalu_offset_Dyad,
                int initvalu_offset_SL,
                int initvalu_offset_Cyt,
                fp *parameter,
                fp *finavalu,
                fp JCaDyad,
                fp JCaSL,
                fp JCaCyt){

	fp BtotDyad;
	fp CaMKIItotDyad;

	fp Vmyo;
	fp Vdyad;
	fp VSL;
	fp kDyadSL;
	fp kSLmyo;
	fp k0Boff;
	fp k0Bon;
	fp k2Boff;
	fp k2Bon;
	fp k4Boff;
	fp k4Bon;
	fp CaMtotDyad;
	fp Bdyad;
	fp J_cam_dyadSL;
	fp J_ca2cam_dyadSL;
	fp J_ca4cam_dyadSL;
	fp J_cam_SLmyo;
	fp J_ca2cam_SLmyo;
	fp J_ca4cam_SLmyo;

	BtotDyad      = parameter[2];
	CaMKIItotDyad = parameter[3];

	Vmyo = 2.1454e-11f;
	Vdyad = 1.7790e-14f;
	VSL = 6.6013e-13f;
	kDyadSL = 3.6363e-16f;
	kSLmyo = 8.587e-15f;
	k0Boff = 0.0014f;
	k0Bon = k0Boff/0.2f;
	k2Boff = k0Boff/100.0f;
	k2Bon = k0Bon;
	k4Boff = k2Boff;
	k4Bon = k0Bon;

	finavalu[initvalu_offset_ecc+35] = finavalu[initvalu_offset_ecc+35] + 1e-3f*JCaDyad;
	finavalu[initvalu_offset_ecc+36] = finavalu[initvalu_offset_ecc+36] + 1e-3f*JCaSL;
	finavalu[initvalu_offset_ecc+37] = finavalu[initvalu_offset_ecc+37] + 1e-3f*JCaCyt;

	CaMtotDyad = initvalu[initvalu_offset_Dyad+0]
			   + initvalu[initvalu_offset_Dyad+1]
			   + initvalu[initvalu_offset_Dyad+2]
			   + initvalu[initvalu_offset_Dyad+3]
			   + initvalu[initvalu_offset_Dyad+4]
			   + initvalu[initvalu_offset_Dyad+5]
			   + CaMKIItotDyad * (  initvalu[initvalu_offset_Dyad+6]
								  + initvalu[initvalu_offset_Dyad+7]
								  + initvalu[initvalu_offset_Dyad+8]
								  + initvalu[initvalu_offset_Dyad+9])
			   + initvalu[initvalu_offset_Dyad+12]
			   + initvalu[initvalu_offset_Dyad+13]
			   + initvalu[initvalu_offset_Dyad+14];
	Bdyad = BtotDyad - CaMtotDyad;
	J_cam_dyadSL = 1e-3f * (  k0Boff*initvalu[initvalu_offset_Dyad+0] - k0Bon*Bdyad*initvalu[initvalu_offset_SL+0]);
	J_ca2cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+1] - k2Bon*Bdyad*initvalu[initvalu_offset_SL+1]);
	J_ca4cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+2] - k4Bon*Bdyad*initvalu[initvalu_offset_SL+2]);

	J_cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]);
	J_ca2cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]);
	J_ca4cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);

	finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL;
	finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL;
	finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;

	finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

	finavalu[initvalu_offset_Cyt+0] = finavalu[initvalu_offset_Cyt+0] + J_cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+1] = finavalu[initvalu_offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+2] = finavalu[initvalu_offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

__device__ void kernel_fin_2(fp timeinst,
