#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#ifndef fp
#define fp float
#endif

#ifndef EQUATIONS
#define EQUATIONS 91
#endif

#ifndef PARAMETERS
#define PARAMETERS 16
#endif

#define max(x,y) ( (x) < (y) ? (y) : (x) )
#define min(x,y) ( (x) < (y) ? (x) : (y) )

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125f
#define MAX_SCALE_FACTOR 4.0f

extern void embedded_fehlberg_7_8(	fp timeinst,
									fp h,
									fp* initvalu,
									fp* finavalu,
									fp* error,
									fp* parameter,
									fp* com,
									fp* d_initvalu,
									fp* d_finavalu,
									fp* d_params,
									fp* d_com);

void write(char* filename,
           fp* input,
           int data_rows,
           int data_cols,
           int major,
           int data_range){

	FILE* fid;
	int i, j;

	fid = fopen(filename, "w");
	if( fid == NULL ){
		printf("The file was not created/opened for writing\n");
		return;
	}

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%f ", (fp)input[i*data_cols+j]);
			}
			fprintf(fid, "\n");
		}
	}
	else{
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%f ", (fp)input[j*data_rows+i]);
			}
			fprintf(fid, "\n");
		}
	}

	fclose(fid);
}

void read(char* filename,
          fp* input,
          int data_rows,
          int data_cols,
          int major){

	FILE* fid;
	int i, j;
	fp temp;

	fid = fopen(filename, "r");
	if( fid == NULL ){
		printf("The file was not opened for reading\n");
		return;
	}

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%f", &temp);
				input[i*data_cols+j] = (fp)temp;
			}
		}
	}
	else{
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%f", &temp);
				input[j*data_rows+i] = (fp)temp;
			}
		}
	}

	fclose(fid);
}

long long get_time() {
	struct timeval tv;
	gettimeofday(&tv, NULL);
	return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

int solver(fp** y,
           fp* x,
           int xmax,
           fp* params,
           int mode) {

	fp err_exponent;
	fp last_interval;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err = (fp *) malloc(EQUATIONS * sizeof(fp));
	fp* scale = (fp *) malloc(EQUATIONS * sizeof(fp));
	fp* yy = (fp *) malloc(EQUATIONS * sizeof(fp));
	fp* com = (fp *) malloc(3 * sizeof(fp));

	fp* d_initvalu = NULL;
	fp* d_finavalu = NULL;
	fp* d_params = NULL;
	fp* d_com = NULL;

	int i, j, k;

	cudaMalloc((void**)&d_initvalu, EQUATIONS * sizeof(fp));
	cudaMalloc((void**)&d_finavalu, EQUATIONS * sizeof(fp));
	cudaMalloc((void**)&d_params, PARAMETERS * sizeof(fp));
	cudaMalloc((void**)&d_com, 3 * sizeof(fp));

	err_exponent = 1.0f / 7.0f;
	last_interval = 0.0f;
	h_init = 1.0f;
	h = h_init;
	xmin = 0;
	tolerance = 10.0f / (fp)(xmax-xmin);

	x[0] = 0.0f;

	if (xmax < xmin || h <= 0.0f){
		cudaFree(d_initvalu);
		cudaFree(d_finavalu);
		cudaFree(d_params);
		cudaFree(d_com);
		free(err);
		free(scale);
		free(yy);
		free(com);
		return -2;
	}

	if (xmax == xmin){
		cudaFree(d_initvalu);
		cudaFree(d_finavalu);
		cudaFree(d_params);
		cudaFree(d_com);
		free(err);
		free(scale);
		free(yy);
		free(com);
		return 0;
	}

	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
		last_interval = 1.0f;
	}

	for(k=1; k<=xmax; k++) {

		x[k] = (fp)(k-1);
		h = h_init;
		scale_fina = 1.0f;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(x[k],
			                      h,
			                      y[k-1],
			                      y[k],
			                      err,
			                      params,
			                      com,
			                      d_initvalu,
			                      d_finavalu,
			                      d_params,
			                      d_com);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0.0f){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0f){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabsf(y[k-1][i]);
				}
				scale[i] = 0.8f * powf( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i] < scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9f) {
				h = 0.9f;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5f * h > (fp)xmax ){
				h = 0.5f * h;
			}
		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			cudaFree(d_initvalu);
			cudaFree(d_finavalu);
			cudaFree(d_params);
			cudaFree(d_com);
			free(err);
			free(scale);
			free(yy);
			free(com);
			return -1;
		}
	}

	cudaFree(d_initvalu);
	cudaFree(d_finavalu);
	cudaFree(d_params);
	cudaFree(d_com);

	free(err);
	free(scale);
	free(yy);
	free(com);

	(void)last_interval;
	(void)mode;

	return 0;
}

