int solver(fp** y,
           fp* x,
           int xmax,
           fp* params,
           int mode) {

    (void)mode;

    fp err_exponent;
    fp last_interval;
    int error_flag;
    int outside;
    fp h;
    fp h_init;
    fp tolerance;
    int xmin;

    fp scale_min;
    fp scale_fina;
    fp* err = (fp *) malloc(EQUATIONS * sizeof(fp));
    fp* scale = (fp *) malloc(EQUATIONS * sizeof(fp));
    fp* yy = (fp *) malloc(EQUATIONS * sizeof(fp));

    fp *d_initvalu = NULL;
    fp *d_finavalu = NULL;
    fp *d_params = NULL;
    fp *d_com = NULL;

    int i, j, k;

    cudaMalloc((void**)&d_initvalu, EQUATIONS * sizeof(fp));
    cudaMalloc((void**)&d_finavalu, EQUATIONS * sizeof(fp));
    cudaMalloc((void**)&d_params, PARAMETERS * sizeof(fp));
    cudaMalloc((void**)&d_com, 3 * sizeof(fp));

    err_exponent = 1.0f / 7.0f;
    last_interval = 0.0f;
    h_init = 1.0f;
    h = h_init;
    xmin = 0;
    tolerance = 10.0f / (fp)(xmax-xmin);

    x[0] = 0.0f;

    if (xmax < xmin || h <= 0.0f){
        cudaFree(d_initvalu);
        cudaFree(d_finavalu);
        cudaFree(d_params);
        cudaFree(d_com);
        free(err);
        free(scale);
        free(yy);
        return -2;
    }

    if (xmax == xmin){
        cudaFree(d_initvalu);
        cudaFree(d_finavalu);
        cudaFree(d_params);
        cudaFree(d_com);
        free(err);
        free(scale);
        free(yy);
        return 0;
    }

    if (h > (xmax - xmin)) {
        h = (fp)xmax - (fp)xmin;
        last_interval = 1.0f;
    }

    for(k=1; k<=xmax; k++) {

        x[k] = (fp)(k-1);
        h = h_init;
        scale_fina = 1.0f;

        for (j = 0; j < ATTEMPTS; j++) {

            error_flag = 0;
            outside = 0;
            scale_min = MAX_SCALE_FACTOR;

            rkf78_step_cuda(x[k], h, y[k-1], y[k], err, params, d_initvalu, d_finavalu, d_params, d_com);

            for(i=0; i<EQUATIONS; i++){
                if(err[i] > 0.0f){
                    error_flag = 1;
                }
            }
            if (error_flag != 1) {
                scale_fina = MAX_SCALE_FACTOR;
                break;
            }

            for(i=0; i<EQUATIONS; i++){
                if(y[k-1][i] == 0.0f){
                    yy[i] = tolerance;
                }
                else{
                    yy[i] = fabsf(y[k-1][i]);
                }
                scale[i] = 0.8f * powf(tolerance * yy[i] / err[i], err_exponent);
                if(scale[i] < scale_min){
                    scale_min = scale[i];
                }
            }
            scale_fina = mymin(mymax(scale_min, MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

            for(i=0; i<EQUATIONS; i++){
                if (err[i] > (tolerance * yy[i])){
                    outside = 1;
                }
            }
            if (outside == 0){
                break;
            }

            h = h * scale_fina;

            if (h >= 0.9f) {
                h = 0.9f;
            }

            if (x[k] + h > (fp)xmax){
                h = (fp)xmax - x[k];
            }
            else if (x[k] + 0.5f * h + h > (fp)xmax){
                h = 0.5f * h;
            }
        }

        x[k] = x[k] + h;

        if (j >= ATTEMPTS) {
            cudaFree(d_initvalu);
            cudaFree(d_finavalu);
            cudaFree(d_params);
            cudaFree(d_com);
            free(err);
            free(scale);
            free(yy);
            return -1;
        }
    }

    cudaFree(d_initvalu);
    cudaFree(d_finavalu);
    cudaFree(d_params);
    cudaFree(d_com);

    free(err);
    free(scale);
    free(yy);

    (void)last_interval;
    return 0;
}

