#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <time.h>
#include <cuda_runtime.h>

#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    double dist;
};

#define CUDA_CHECK(call)                                                          \
    do {                                                                          \
        cudaError_t err__ = (call);                                               \
        if (err__ != cudaSuccess) {                                               \
            fprintf(stderr, "CUDA error: %s\n", cudaGetErrorString(err__));       \
            exit(1);                                                              \
        }                                                                         \
    } while (0)

__device__ float parse_float_device(const char *p) {
    while (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r' ||
           *p == '\f' || *p == '\v') {
        ++p;
    }

    int sign = 1;
    if (*p == '-') {
        sign = -1;
        ++p;
    } else if (*p == '+') {
        ++p;
    }

    float value = 0.0f;
    bool any = false;

    while (*p >= '0' && *p <= '9') {
        value = value * 10.0f + (float)(*p - '0');
        ++p;
        any = true;
    }

    if (*p == '.') {
        ++p;
        float place = 0.1f;
        while (*p >= '0' && *p <= '9') {
            value += (float)(*p - '0') * place;
            place *= 0.1f;
            ++p;
            any = true;
        }
    }

    if (!any) return 0.0f;
    return sign * value;
}

__global__ void compute_distances_kernel(const char *sandbox, float *z, int rec_count,
                                         float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        const char *rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);
        float tmp_lat = parse_float_device(rec_iter);
        float tmp_long = parse_float_device(rec_iter + 5);

        double dlat = (double)tmp_lat - (double)target_lat;
        double dlong = (double)tmp_long - (double)target_long;
        z[i] = (float)sqrt(dlat * dlat + dlong * dlong);
    }
}

int main(int argc, char* argv[]) {
    long long time0 = clock();
    FILE *flist, *fp;
    int i = 0, j = 0, k = 0, rec_count = 0, done = 0;
    char sandbox[REC_LENGTH * REC_WINDOW], *rec_iter, *rec_iter2, dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long, tmp_lat = 0, tmp_long = 0;

    if (argc < 5) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if (!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = atof(argv[3]);
    target_long = atof(argv[4]);

    neighbors = (struct neighbor *)malloc(k * sizeof(struct neighbor));

    if (neighbors == NULL) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for (j = 0; j < k; j++) {
        neighbors[j].dist = OPEN;
    }

    if (fscanf(flist, "%s\n", dbname) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    fp = fopen(dbname, "r");
    if (!fp) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z;
    z = (float *)malloc(REC_WINDOW * sizeof(float));

    char *d_sandbox = NULL;
    float *d_z = NULL;
    CUDA_CHECK(cudaMalloc((void **)&d_sandbox, REC_LENGTH * REC_WINDOW * sizeof(char)));
    CUDA_CHECK(cudaMalloc((void **)&d_z, REC_WINDOW * sizeof(float)));

    while (!done) {
        rec_count = (int)fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
        if (rec_count != REC_WINDOW) {
            if (!ferror(flist)) {
                fclose(fp);

                if (feof(flist))
                    done = 1;
                else {
                    if (fscanf(flist, "%s\n", dbname) != 1) {
                        fprintf(stderr, "error reading filelist\n");
                        exit(0);
                    }

                    fp = fopen(dbname, "r");

                    if (!fp) {
                        printf("error opening a db\n");
                        exit(1);
                    }
                }
            } else {
                perror("Error");
                exit(0);
            }
        }

        if (rec_count > 0) {
            CUDA_CHECK(cudaMemcpy(d_sandbox, sandbox,
                                  REC_LENGTH * REC_WINDOW * sizeof(char),
                                  cudaMemcpyHostToDevice));

            int threads = 32;
            int blocks = (rec_count + threads - 1) / threads;
            compute_distances_kernel<<<blocks, threads>>>(d_sandbox, d_z, rec_count,
                                                          target_lat, target_long);
            CUDA_CHECK(cudaGetLastError());
            CUDA_CHECK(cudaDeviceSynchronize());

            CUDA_CHECK(cudaMemcpy(z, d_z, REC_WINDOW * sizeof(float),
                                  cudaMemcpyDeviceToHost));
        }

        for (i = 0; i < rec_count; i++) {
            float max_dist = -1;
            int max_idx = 0;

            for (j = 0; j < k; j++) {
                if (neighbors[j].dist > max_dist) {
                    max_dist = (float)neighbors[j].dist;
                    max_idx = j;
                }
            }

            if (z[i] < neighbors[max_idx].dist) {
                sandbox[(i + 1) * REC_LENGTH - 1] = '\0';
                strcpy(neighbors[max_idx].entry, sandbox + i * REC_LENGTH);
                neighbors[max_idx].dist = z[i];
            }
        }
    }

    fprintf(stderr, "The %d nearest neighbors are:\n", k);
    for (j = 0; j < k; j++) {
        if (!(neighbors[j].dist == OPEN))
            fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
    }

    fclose(flist);

    CUDA_CHECK(cudaFree(d_sandbox));
    CUDA_CHECK(cudaFree(d_z));
    free(z);
    free(neighbors);

    long long time1 = clock();
    printf("total time : %15.12f s", (float)(time1 - time0) / 1000000);
    return 0;
}

