__device__ float parse_float_field(const char *s) {
    int idx = 0;
    while (s[idx] == ' ' || s[idx] == '\t') idx++;

    int sign = 1;
    if (s[idx] == '-') {
        sign = -1;
        idx++;
    } else if (s[idx] == '+') {
        idx++;
    }

    float value = 0.0f;
    while (s[idx] >= '0' && s[idx] <= '9') {
        value = value * 10.0f + (float)(s[idx] - '0');
        idx++;
    }

    if (s[idx] == '.') {
        idx++;
        float place = 0.1f;
        while (s[idx] >= '0' && s[idx] <= '9') {
            value += (float)(s[idx] - '0') * place;
            place *= 0.1f;
            idx++;
        }
    }

    return sign * value;
}

__global__ void compute_distances(const char *sandbox, float *z, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        const char *rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);
        float tmp_lat = parse_float_field(rec_iter);
        float tmp_long = parse_float_field(rec_iter + 5);
        float dlat = tmp_lat - target_lat;
        float dlong = tmp_long - target_long;
        z[i] = sqrtf(dlat * dlat + dlong * dlong);
    }
}

