static inline __host__ __device__ int maximum_cuda(int a, int b, int c)
{
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

static void cuda_check(cudaError_t err, const char *msg)
{
    if (err != cudaSuccess)
    {
        fprintf(stderr, "CUDA error at %s: %s\n", msg, cudaGetErrorString(err));
        exit(1);
    }
}

__global__ void needle_top_left_kernel(int *input_itemsets, const int *referrence,
                                       int max_cols, int penalty, int blk)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= blk)
        return;

    int b_index_x = tid;
    int b_index_y = blk - 1 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum_cuda(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                        reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void needle_bottom_right_kernel(int *input_itemsets, const int *referrence,
                                           int max_cols, int penalty,
                                           int blk, int total_blocks)
{
    int tile_count = total_blocks - blk + 1;
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= tile_count)
        return;

    int b_index_x = blk - 1 + tid;
    int b_index_y = total_blocks - 1 - tid;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum_cuda(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                        reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
                  int max_rows, int max_cols, int penalty)
{
    (void)max_rows;

    int *d_input_itemsets = NULL;
    int *d_referrence = NULL;
    size_t transfer_size = (size_t)max_rows * (size_t)max_cols * sizeof(int);

    cuda_check(cudaMalloc((void **)&d_input_itemsets, transfer_size), "cudaMalloc d_input_itemsets");
    cuda_check(cudaMalloc((void **)&d_referrence, transfer_size), "cudaMalloc d_referrence");

    cuda_check(cudaMemcpy(d_input_itemsets, input_itemsets, transfer_size, cudaMemcpyHostToDevice),
               "cudaMemcpy input_itemsets H2D");
    cuda_check(cudaMemcpy(d_referrence, referrence, transfer_size, cudaMemcpyHostToDevice),
               "cudaMemcpy referrence H2D");

    int total_blocks = (max_cols - 1) / BLOCK_SIZE;
    int threads = 128;

    for (int blk = 1; blk <= total_blocks; blk++)
    {
        int tile_count = blk;
        int grid = (tile_count + threads - 1) / threads;
        needle_top_left_kernel<<<grid, threads>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk);
        cuda_check(cudaGetLastError(), "needle_top_left_kernel launch");
        cuda_check(cudaDeviceSynchronize(), "needle_top_left_kernel sync");
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= total_blocks; blk++)
    {
        int tile_count = total_blocks - blk + 1;
        int grid = (tile_count + threads - 1) / threads;
        needle_bottom_right_kernel<<<grid, threads>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk, total_blocks);
        cuda_check(cudaGetLastError(), "needle_bottom_right_kernel launch");
        cuda_check(cudaDeviceSynchronize(), "needle_bottom_right_kernel sync");
    }

    cuda_check(cudaMemcpy(input_itemsets, d_input_itemsets, transfer_size, cudaMemcpyDeviceToHost),
               "cudaMemcpy input_itemsets D2H");

    if (output_itemsets != NULL)
    {
        cuda_check(cudaMemcpy(output_itemsets, d_input_itemsets, transfer_size, cudaMemcpyDeviceToHost),
                   "cudaMemcpy output_itemsets D2H");
    }

    cuda_check(cudaFree(d_input_itemsets), "cudaFree d_input_itemsets");
    cuda_check(cudaFree(d_referrence), "cudaFree d_referrence");
}

