__global__ static void srad_kernel_1(
	const float *J,
	float *dN,
	float *dS,
	float *dW,
	float *dE,
	float *c,
	int rows,
	int cols,
	float q0sqr)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;

		int iN = (i == 0) ? 0 : (i - 1);
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jW = (j == 0) ? 0 : (j - 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float Jc = J[k];

		float dNk = J[iN * cols + j] - Jc;
		float dSk = J[iS * cols + j] - Jc;
		float dWk = J[i * cols + jW] - Jc;
		float dEk = J[i * cols + jE] - Jc;

		dN[k] = dNk;
		dS[k] = dSk;
		dW[k] = dWk;
		dE[k] = dEk;

		float G2 = (dNk * dNk + dSk * dSk + dWk * dWk + dEk * dEk) / (Jc * Jc);
		float L = (dNk + dSk + dWk + dEk) / Jc;

		float num = (0.5f * G2) - (0.0625f * (L * L));
		float den = 1.0f + (0.25f * L);
		float qsqr = num / (den * den);

		den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
		float ck = 1.0f / (1.0f + den);

		if (ck < 0.0f) ck = 0.0f;
		else if (ck > 1.0f) ck = 1.0f;

		c[k] = ck;
	}
}

__global__ static void srad_kernel_2(
	float *J,
	const float *c,
	const float *dN,
	const float *dS,
	const float *dW,
	const float *dE,
	int rows,
	int cols,
	float lambda)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;

		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float cN = c[k];
		float cS = c[iS * cols + j];
		float cW = c[k];
		float cE = c[i * cols + jE];

