    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j) {
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return (1);
  if (a < b) return (-1);
  return (0);
}

void shuffle(Points *points) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

void intshuffle(int *intarray, int length) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48() % (length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

#ifdef INSERT_WASTE
double waste(double s) {
  for (int i = 0; i < 4; i++) {
    s += pow(s, 0.78);
  }
  return s;
}
#endif

static inline __host__ __device__ float dist_point(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0f;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  double s = waste(result);
  result += s;
  result -= s;
#endif
  return result;
}

float dist(Point p1, Point p2, int dim) {
  return dist_point(p1, p2, dim);
}

__global__ void pgain_compute_kernel(Point *p, long n, int dim, long x,
                                     bool *switch_membership_dev,
                                     int *center_table_dev,
                                     double *delta_dev,
                                     int *lower_index_dev) {
  long i = (long)blockIdx.x * blockDim.x + threadIdx.x;
  if (i >= n) return;

  float x_cost = dist_point(p[i], p[x], dim) * p[i].weight;
  float current_cost = p[i].cost;

  if (x_cost < current_cost) {
    switch_membership_dev[i] = true;
    delta_dev[i] = (double)(x_cost - current_cost);
    lower_index_dev[i] = -1;
  } else {
    switch_membership_dev[i] = false;
    delta_dev[i] = (double)(current_cost - x_cost);
    int assign = (int)p[i].assign;
    lower_index_dev[i] = center_table_dev[assign];
  }
}

__global__ void pgain_apply_kernel(Point *p, long n, int dim, long x,
                                   bool *switch_membership_dev,
                                   int *center_table_dev,
                                   double *gl_lower_dev) {
  long i = (long)blockIdx.x * blockDim.x + threadIdx.x;
  if (i >= n) return;

  bool close_center = gl_lower_dev[center_table_dev[p[i].assign]] > 0.0;
  if (switch_membership_dev[i] || close_center) {
    p[i].cost = p[i].weight * dist_point(p[i], p[x], dim);
    p[i].assign = x;
  }
}

float pspeedy(Points *points, float z, long *kcenter, int /*pid*/) {
#ifdef PROFILE
  double t1 = gettime();
#endif

#ifdef PRINTINFO
  fprintf(stderr, "Speedy: facility cost %lf\n", z);
#endif

  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (long i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
    }
  }

  double totalcost = z * (*kcenter);
  for (long k = 0; k < points->num; k++) {
    totalcost += points->p[k].cost;
  }

#ifdef PRINTINFO
  fprintf(stderr, "Speedy opened %ld facilities for total cost %lf\n",
          *kcenter, totalcost);
  fprintf(stderr, "Distance Cost %lf\n", totalcost - z * (*kcenter));
#endif

#ifdef PROFILE
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return (float)totalcost;
}

double pgain(long x, Points *points, double z, long int *numcenters, int /*pid*/) {
#ifdef PROFILE
  double t0 = gettime();
#endif

  long n = points->num;
  int number_of_centers_to_close = 0;
  double cost_of_opening_x = 0.0;

  int count = 0;
  for (long i = 0; i < n; i++) {
    if (is_center[i]) {
      center_table[i] = count++;
    }
  }

  memset(switch_membership, 0, n * sizeof(bool));

  double *lower = (double *)calloc((count > 0 ? count : 1), sizeof(double));
  double *gl_lower_host = (double *)calloc((count > 0 ? count : 1), sizeof(double));
  double *delta_dev = managedAlloc<double>(n > 0 ? n : 1);
  int *lower_index_dev = managedAlloc<int>(n > 0 ? n : 1);

#ifdef PROFILE
  double t1 = gettime();
  time_gain_init += t1 - t0;
#endif

  if (n > 0) {
    int threads = 256;
    int blocks = (int)((n + threads - 1) / threads);
    pgain_compute_kernel<<<blocks, threads>>>(points->p, n, points->dim, x,
                                              switch_membership, center_table,
                                              delta_dev, lower_index_dev);
    cudaCheck(cudaGetLastError(), "pgain_compute_kernel launch");
    cudaCheck(cudaDeviceSynchronize(), "pgain_compute_kernel sync");
  }

  for (long i = 0; i < n; i++) {
    if (lower_index_dev[i] < 0) {
      cost_of_opening_x += delta_dev[i];
    } else {
      lower[lower_index_dev[i]] += delta_dev[i];
    }
  }

#ifdef PROFILE
  double t2 = gettime();
  time_gain_dist += t2 - t1;
#endif

  for (long i = 0; i < n; i++) {
    if (is_center[i]) {
      double low = z + lower[center_table[i]];
      gl_lower_host[center_table[i]] = low;
      if (low > 0) {
        ++number_of_centers_to_close;
        cost_of_opening_x -= low;
      }
    }
  }

  double gl_cost_of_opening_x = z + cost_of_opening_x;
  int gl_number_of_centers_to_close = number_of_centers_to_close;

  if (gl_cost_of_opening_x < 0) {
    double *gl_lower_dev = managedAlloc<double>(count > 0 ? count : 1);
    for (int i = 0; i < count; i++) gl_lower_dev[i] = gl_lower_host[i];

    if (n > 0) {
      int threads = 256;
      int blocks = (int)((n + threads - 1) / threads);
      pgain_apply_kernel<<<blocks, threads>>>(points->p, n, points->dim, x,
                                              switch_membership, center_table,
                                              gl_lower_dev);
      cudaCheck(cudaGetLastError(), "pgain_apply_kernel launch");
      cudaCheck(cudaDeviceSynchronize(), "pgain_apply_kernel sync");
    }

    for (long i = 0; i < n; i++) {
      if (is_center[i] && gl_lower_host[center_table[i]] > 0) {
        is_center[i] = false;
      }
    }
    is_center[x] = true;
    *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;

    cudaCheck(cudaFree(gl_lower_dev), "cudaFree gl_lower_dev");
  } else {
    gl_cost_of_opening_x = 0;
  }

  cudaCheck(cudaFree(delta_dev), "cudaFree delta_dev");
  cudaCheck(cudaFree(lower_index_dev), "cudaFree lower_index_dev");
  free(lower);
  free(gl_lower_host);

#ifdef PROFILE
  double t3 = gettime();
  time_gain += t3 - t0;
#endif

  return -gl_cost_of_opening_x;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, double cost, long iter, float e,
          int pid) {
  long i;
  long x;
  double change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;
    (void)numberOfPoints;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, pid);
      c++;
    }

    cost -= change;
#ifdef PRINTINFO
    fprintf(stderr, "%ld centers, cost %lf, total distance %lf\n",
            *k, cost, cost - z * (*k));
#endif
  }
  return (float)cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int /*pid*/) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((double)kmin)))
    numfeasible = (int)(ITER * kmin * log((double)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  float *accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < k2; i++)
      (*feasible)[i] = i;
#ifdef PROFILE
    double t2 = gettime();
    time_select_feasible += t2 - t1;
#endif
    return numfeasible;
  }

  accumweight = (float *)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }

  free(accumweight);

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal, int pid) {
  int i;
  double cost;
  double lastcost;
  double hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;

  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

#ifdef PRINTINFO
  printf("Starting Kmedian procedure\n");
  printf("%ld points in %ld dimensions\n", numberOfPoints, ptDimension);
#endif

  double myhiz = 0;
  for (long kk = 0; kk < points->num; kk++) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }
  hiz = myhiz;

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = k;
    return (float)cost;
  }

  shuffle(points);
  cost = pspeedy(points, (float)z, &k, pid);

#ifdef PRINTINFO
  printf("thread %d: Finished first call to speedy, cost=%lf, k=%ld\n", pid, cost, k);
#endif

  i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, (float)z, &k, pid);
    i++;
  }

#ifdef PRINTINFO
  printf("thread %d: second call to speedy, cost=%lf, k=%ld\n", pid, cost, k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    printf("%lf %lf\n", loz, hiz);
    printf("Speedy indicates we should try lower z\n");
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, (float)z, &k, pid);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin, pid);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
    d++;
#ifdef PRINTINFO
    printf("loz = %lf, hiz = %lf\n", loz, hiz);
    printf("Running Local Search...\n");
#endif

    lastcost = cost;
    (void)lastcost;

    cost = pFL(points, feasible, numfeasible,
               (float)z, &k, cost, (long)(ITER * kmax * log((double)kmax)), 0.1f, pid);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      printf("Trying a more accurate local search...\n");
#endif
      cost = pFL(points, feasible, numfeasible,
                 (float)z, &k, cost, (long)(ITER * kmax * log((double)kmax)), 0.001f, pid);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;

  return (float)cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] +=
            points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  pkmedian(points, kmin, kmax, kfinal, 0);

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

class PStream {
public:
  virtual size_t read(float *dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) { n = n_; }
  size_t read(float *dest, int dim, int num) {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() { return 0; }
  int feof() { return n <= 0; }
  ~SimStream() {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char *filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float *dest, int dim, int num) {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() { return std::ferror(fp); }
  int feof() { return std::feof(fp); }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE *fp;
};

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
  FILE *fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int *is_a_median = (int *)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", (unsigned)centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream *stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char *outfile) {
  block = managedAlloc<float>(chunksize * dim);
  float *centerBlock = managedAlloc<float>(centersize * dim);
  long *centerIDs = (long *)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = managedAlloc<Point>(chunksize);
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = managedAlloc<Point>(centersize);
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
    centers.p[i].assign = 0;
    centers.p[i].cost = 0.0f;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %d points\n", (int)numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
      points.p[i].assign = 0;
      points.p[i].cost = 0.0f;
    }

    switch_membership = managedAlloc<bool>(points.num > 0 ? points.num : 1);
    is_center = managedCalloc<bool>(points.num > 0 ? points.num : 1);
    center_table = managedAlloc<int>(points.num > 0 ? points.num : 1);

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif

    cudaCheck(cudaFree(is_center), "cudaFree is_center");
    cudaCheck(cudaFree(switch_membership), "cudaFree switch_membership");
    cudaCheck(cudaFree(center_table), "cudaFree center_table");

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = managedAlloc<bool>(centers.num > 0 ? centers.num : 1);
  is_center = managedCalloc<bool>(centers.num > 0 ? centers.num : 1);
  center_table = managedAlloc<int>(centers.num > 0 ? centers.num : 1);

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  cudaCheck(cudaFree(is_center), "cudaFree is_center final");
  cudaCheck(cudaFree(switch_membership), "cudaFree switch_membership final");
  cudaCheck(cudaFree(center_table), "cudaFree center_table final");
  cudaCheck(cudaFree(points.p), "cudaFree points.p");
  cudaCheck(cudaFree(centers.p), "cudaFree centers.p");
  cudaCheck(cudaFree(block), "cudaFree block");
  cudaCheck(cudaFree(centerBlock), "cudaFree centerBlock");
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
  c = 0;
  d = 0;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 10) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n",
            argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  ompthreads = nproc;
  nproc = 1;

  srand48(SEED);
  PStream *stream;
  if (n > 0) {
    stream = new SimStream(n);
  } else {
    stream = new FileStream(infilename);
  }

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

  double t2 = gettime();

  printf("time = %lf\n", t2 - t1);

  delete stream;

  printf("time pgain = %lf\n", time_gain);
  printf("time pgain_dist = %lf\n", time_gain_dist);
  printf("time pgain_init = %lf\n", time_gain_init);
  printf("time pselect = %lf\n", time_select_feasible);
  printf("time pspeedy = %lf\n", time_speedy);
  printf("time pshuffle = %lf\n", time_shuffle);
  printf("time localSearch = %lf\n", time_local_search);
  printf("loops=%d\n", d);

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  delete[] outfilename;
  delete[] infilename;
  return 0;
}

#include <stdio.h>
#include <iostream>
