using namespace std;

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define PROFILE
#define CACHE_LINE 512

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

static bool *switch_membership;
static bool *is_center;
static int *center_table;
float *block;

static int nproc;
static int c, d;
static int ompthreads;

#ifdef PROFILE
double time_local_search;
double time_speedy;
double time_select_feasible;
double time_gain;
double time_shuffle;
double time_gain_dist;
double time_gain_init;
#endif

extern void cuda_pgain_first(Points *points, long x, bool *switch_membership,
                             int *center_table, double *lower,
                             double *cost_of_opening_x);
extern void cuda_pgain_update(Points *points, long x, bool *switch_membership,
                              int *center_table, double *gl_lower);

static int g_cuda_available = -1;

static int cuda_backend_available() {
  if (g_cuda_available == -1) {
    int count = 0;
    cudaError_t err = cudaGetDeviceCount(&count);
    if (err == cudaSuccess && count > 0) {
      g_cuda_available = 1;
    } else {
      g_cuda_available = 0;
      cudaGetLastError();
    }
  }
  return g_cuda_available;
}

template <typename T>
static T *managed_alloc(size_t n) {
  if (n == 0) return NULL;
  T *ptr = NULL;
  if (cuda_backend_available()) {
    cudaError_t err = cudaMallocManaged((void **)&ptr, n * sizeof(T));
    if (err != cudaSuccess) {
      fprintf(stderr, "cudaMallocManaged failed: %s\n", cudaGetErrorString(err));
      exit(1);
    }
  } else {
    ptr = (T *)malloc(n * sizeof(T));
    if (ptr == NULL) {
      fprintf(stderr, "not enough memory!\n");
      exit(1);
    }
  }
  return ptr;
}

template <typename T>
static T *managed_calloc(size_t n) {
  T *ptr = managed_alloc<T>(n);
  if (ptr && n > 0) memset(ptr, 0, n * sizeof(T));
  return ptr;
}

template <typename T>
static void managed_free(T *ptr) {
  if (ptr == NULL) return;
  if (cuda_backend_available()) cudaFree(ptr);
  else free(ptr);
}

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return (double)t.tv_sec + t.tv_usec * 1e-6;
}

int isIdentical(float *i, float *j, int D) {
  int a = 0;
  int equal = 1;

  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j) {
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return (1);
  if (a < b) return (-1);
  return (0);
}

void shuffle(Points *points) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

void intshuffle(int *intarray, int length) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48() % (length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

float dist(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
  return result;
}

float pspeedy(Points *points, float z, long *kcenter, int pid,
              pthread_barrier_t *barrier) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  (void)pid;
  (void)barrier;

  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (long i = 1; i < points->num; i++) {
    bool to_open =
        ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
    }
  }

  double totalcost = z * (*kcenter);
  for (long k = 0; k < points->num; k++) {
    totalcost += points->p[k].cost;
  }

#ifdef PROFILE
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return (float)totalcost;
}

double pgain(long x, Points *points, double z, long int *numcenters, int pid,
             pthread_barrier_t *barrier) {
  (void)pid;
  (void)barrier;

#ifdef PROFILE
  double t0 = gettime();
#endif

  int number_of_centers_to_close = 0;

  int stride = *numcenters + 2;
  int cl = CACHE_LINE / sizeof(double);
  if (stride % cl != 0) {
    stride = cl * (stride / cl + 1);
  }
  int K = stride - 2;

  double *work_mem = managed_calloc<double>(stride * (nproc + 1));
  double *cost_of_opening_x_buf = managed_calloc<double>(1);

  int count = 0;
  for (long i = 0; i < points->num; i++) {
    if (is_center[i]) {
      center_table[i] = count++;
    }
  }

  if (points->num > 0) memset(switch_membership, 0, points->num * sizeof(bool));
  memset(work_mem, 0, stride * (nproc + 1) * sizeof(double));

#ifdef PROFILE
  double t1 = gettime();
  time_gain_init += t1 - t0;
#endif

  double *lower = &work_mem[0];
  double *gl_lower = &work_mem[nproc * stride];

  cuda_pgain_first(points, x, switch_membership, center_table, lower,
                   cost_of_opening_x_buf);

  double cost_of_opening_x = *cost_of_opening_x_buf;

#ifdef PROFILE
  double t2 = gettime();
  time_gain_dist += t2 - t1;
#endif

  for (long i = 0; i < points->num; i++) {
    if (is_center[i]) {
      double low = z;
      low += lower[center_table[i]];
      gl_lower[center_table[i]] = low;

      if (low > 0) {
        ++number_of_centers_to_close;
        cost_of_opening_x -= low;
      }
    }
  }

  work_mem[K] = number_of_centers_to_close;
  work_mem[K + 1] = cost_of_opening_x;

  double gl_cost_of_opening_x = z + work_mem[K + 1];
  int gl_number_of_centers_to_close = (int)work_mem[K];

  if (gl_cost_of_opening_x < 0) {
    cuda_pgain_update(points, x, switch_membership, center_table, gl_lower);

    for (long i = 0; i < points->num; i++) {
      if (is_center[i] && gl_lower[center_table[i]] > 0) {
        is_center[i] = false;
      }
    }
    if (x >= 0 && x < points->num) {
      is_center[x] = true;
    }

    *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  managed_free(cost_of_opening_x_buf);
  managed_free(work_mem);

#ifdef PROFILE
  double t3 = gettime();
  time_gain += t3 - t0;
#endif

  return -gl_cost_of_opening_x;
}

float pFL(Points *points, int *feasible, int numfeasible, float z, long *k,
          double cost, long iter, float e, int pid,
          pthread_barrier_t *barrier) {
  (void)pid;
  (void)barrier;

  long i;
  long x;
  double change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;
    (void)numberOfPoints;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, 0, NULL);
      c++;
    }

    cost -= change;
  }
  return (float)cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid,
                        pthread_barrier_t *barrier) {
  (void)pid;
  (void)barrier;

#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = points->num;
  if (numfeasible > (ITER * kmin * log((double)kmin)))
    numfeasible = (int)(ITER * kmin * log((double)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  float *accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = k1; i < k2; i++) (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight = (float *)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = k1; i < k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }

  free(accumweight);

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal, int pid,
               pthread_barrier_t *barrier) {
  (void)pid;
  (void)barrier;

  int i;
  double cost;
  double lastcost;
  double hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;

  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;
  (void)numberOfPoints;

  for (long kk = 0; kk < points->num; kk++) {
    hiz += dist(points->p[kk], points->p[0], ptDimension) *
           points->p[kk].weight;
  }

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = k;
    return (float)cost;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k, 0, NULL);

  i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, 0, NULL);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k, 0, NULL);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, kmin, 0, NULL);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
    d++;
    lastcost = cost;
    (void)lastcost;

    cost = pFL(points, feasible, numfeasible, z, &k, cost,
               (long)(ITER * kmax * log((double)kmax)), 0.1, 0, NULL);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible, z, &k, cost,
                 (long)(ITER * kmax * log((double)kmax)), 0.001, 0, NULL);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;

  return (float)cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight =
          points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] +=
            points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord,
             points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  pkmedian(points, kmin, kmax, kfinal, 0, NULL);

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

class PStream {
public:
  virtual size_t read(float *dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) { n = n_; }
  size_t read(float *dest, int dim, int num) {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() { return 0; }
  int feof() { return n <= 0; }
  ~SimStream() {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char *filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float *dest, int dim, int num) {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() { return std::ferror(fp); }
  int feof() { return std::feof(fp); }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE *fp;
};

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
  FILE *fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int *is_a_median = (int *)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
}

void streamCluster(PStream *stream, long kmin, long kmax, int dim,
                   long chunksize, long centersize, char *outfile) {
  block = managed_alloc<float>(chunksize * dim);
  float *centerBlock = managed_alloc<float>(centersize * dim);
  long *centerIDs = (long *)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = managed_alloc<Point>(chunksize);
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = managed_alloc<Point>(centersize);
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %d points\n", numRead);

    if (stream->ferror() ||
        (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = managed_alloc<bool>(points.num);
    is_center = managed_calloc<bool>(points.num);
    center_table = managed_alloc<int>(points.num);

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

    managed_free(is_center);
    managed_free(switch_membership);
    managed_free(center_table);

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = managed_alloc<bool>(centers.num);
  is_center = managed_calloc<bool>(centers.num);
  center_table = managed_alloc<int>(centers.num);

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
  int numthreads;
  (void)numthreads;

  c = 0;
  d = 0;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION)
         "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 10) {
    fprintf(stderr,
            "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n",
            argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "\n");
    fprintf(stderr,
            "if n > 0, points will be randomly generated instead of reading "
            "from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  ompthreads = nproc;
  nproc = 1;

  srand48(SEED);
  PStream *stream;
  if (n > 0) {
