} Points;

static int g_cuda_available_k = -1;

static int cuda_backend_available_k() {
  if (g_cuda_available_k == -1) {
    int count = 0;
    cudaError_t err = cudaGetDeviceCount(&count);
    if (err == cudaSuccess && count > 0) {
      g_cuda_available_k = 1;
    } else {
      g_cuda_available_k = 0;
      cudaGetLastError();
    }
  }
  return g_cuda_available_k;
}

__device__ inline double atomicAdd_double_local(double *address, double val) {
#if __CUDA_ARCH__ >= 600
  return atomicAdd(address, val);
#else
  unsigned long long int *address_as_ull =
      (unsigned long long int *)address;
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val +
                                         __longlong_as_double(assumed)));
  } while (assumed != old);
  return __longlong_as_double(old);
#endif
}

__device__ inline float dist_device(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float diff = p1.coord[i] - p2.coord[i];
    result += diff * diff;
  }
  return result;
}

__global__ void pgain_first_kernel(Point *p, long num, int dim, long x,
                                   bool *switch_membership,
                                   int *center_table, double *lower,
                                   double *cost_of_opening_x) {
  long i = (long)blockIdx.x * blockDim.x + threadIdx.x;
  if (i >= num) return;

  float x_cost = dist_device(p[i], p[x], dim) * p[i].weight;
  float current_cost = p[i].cost;

  if (x_cost < current_cost) {
    switch_membership[i] = true;
    atomicAdd_double_local(cost_of_opening_x,
                           (double)(x_cost - current_cost));
  } else {
    int assign = p[i].assign;
    atomicAdd_double_local(&lower[center_table[assign]],
                           (double)(current_cost - x_cost));
  }
}

__global__ void pgain_update_kernel(Point *p, long num, int dim, long x,
                                    bool *switch_membership,
                                    int *center_table, double *gl_lower) {
  long i = (long)blockIdx.x * blockDim.x + threadIdx.x;
  if (i >= num) return;

  bool close_center = gl_lower[center_table[p[i].assign]] > 0;
  if (switch_membership[i] || close_center) {
    p[i].cost = p[i].weight * dist_device(p[i], p[x], dim);
    p[i].assign = x;
  }
}

static inline float dist_host(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float diff = p1.coord[i] - p2.coord[i];
    result += diff * diff;
  }
  return result;
}

void cuda_pgain_first(Points *points, long x, bool *switch_membership,
                      int *center_table, double *lower,
                      double *cost_of_opening_x) {
  if (points->num <= 0) return;

  if (!cuda_backend_available_k()) {
    for (long i = 0; i < points->num; i++) {
      float x_cost =
          dist_host(points->p[i], points->p[x], points->dim) *
          points->p[i].weight;
      float current_cost = points->p[i].cost;

      if (x_cost < current_cost) {
        switch_membership[i] = true;
        *cost_of_opening_x += (double)(x_cost - current_cost);
      } else {
        int assign = points->p[i].assign;
        lower[center_table[assign]] += (double)(current_cost - x_cost);
      }
    }
    return;
  }

  int threads = 256;
  int blocks = (int)((points->num + threads - 1) / threads);
  pgain_first_kernel<<<blocks, threads>>>(points->p, points->num, points->dim,
                                          x, switch_membership, center_table,
                                          lower, cost_of_opening_x);
  cudaDeviceSynchronize();
}

void cuda_pgain_update(Points *points, long x, bool *switch_membership,
                       int *center_table, double *gl_lower) {
  if (points->num <= 0) return;

  if (!cuda_backend_available_k()) {
    for (long i = 0; i < points->num; i++) {
      bool close_center =
          gl_lower[center_table[points->p[i].assign]] > 0;
      if (switch_membership[i] || close_center) {
        points->p[i].cost =
            points->p[i].weight *
            dist_host(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }
    return;
  }

  int threads = 256;
  int blocks = (int)((points->num + threads - 1) / threads);
  pgain_update_kernel<<<blocks, threads>>>(points->p, points->num,
                                           points->dim, x,
                                           switch_membership, center_table,
                                           gl_lower);
  cudaDeviceSynchronize();
}

