float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t *barrier) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  long bsize = points->num / nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if (pid == nproc - 1)
    k2 = points->num;

  static double totalcost;
  static double *costs;

#ifdef PRINTINFO
  if (pid == 0) {
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  for (int k = (int)k1; k < k2; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  if (pid == 0) {
    *kcenter = 1;
    costs = (double *)malloc(sizeof(double) * nproc);
  }

  if (pid == 0) {
    for (int i = 1; i < points->num; i++) {
      bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
      if (to_open) {
        (*kcenter)++;
        for (int k = (int)k1; k < k2; k++) {
          float distance = dist(points->p[i], points->p[k], points->dim);
          if (distance * points->p[k].weight < points->p[k].cost) {
            points->p[k].cost = distance * points->p[k].weight;
            points->p[k].assign = i;
          }
        }
      }
    }
  }

  double mytotal = 0;
  for (int k = (int)k1; k < k2; k++) {
    mytotal += points->p[k].cost;
  }
  costs[pid] = mytotal;

  if (pid == 0) {
    totalcost = z * (*kcenter);
    for (int i = 0; i < nproc; i++) {
      totalcost += costs[i];
    }
    free(costs);
  }

#ifdef PRINTINFO
  if (pid == 0) {
    fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n", (int)*kcenter, totalcost);
    fprintf(stderr, "Distance Cost %lf\n", totalcost - z * (*kcenter));
  }
#endif

#ifdef PROFILE
  double t2 = gettime();
  if (pid == 0) {
    time_speedy += t2 - t1;
  }
#endif
  return (float)totalcost;
}

double pgain(long x, Points *points, double z, long int *numcenters, int pid, pthread_barrier_t *barrier) {
#ifdef PROFILE
  double t0 = gettime();
#endif

  long bsize = points->num / nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if (pid == nproc - 1)
    k2 = points->num;

  int number_of_centers_to_close = 0;

  static double *work_mem;
  static double gl_cost_of_opening_x;
  static int gl_number_of_centers_to_close;

  int stride = (int)(*numcenters) + 2;
  int cl = CACHE_LINE / sizeof(double);
  if (stride % cl != 0) {
    stride = cl * (stride / cl + 1);
  }
  int K = stride - 2;

  double cost_of_opening_x = 0;

  if (pid == 0) {
    work_mem = (double *)malloc(stride * (nproc + 1) * sizeof(double));
    gl_cost_of_opening_x = 0;
    gl_number_of_centers_to_close = 0;
  }

  int count = 0;
  for (int i = (int)k1; i < k2; i++) {
    if (is_center[i]) {
      center_table[i] = count++;
    }
  }
  work_mem[pid * stride] = count;

  if (pid == 0) {
    int accum = 0;
    for (int p = 0; p < nproc; p++) {
      int tmp = (int)work_mem[p * stride];
      work_mem[p * stride] = accum;
      accum += tmp;
    }
  }

  for (int i = (int)k1; i < k2; i++) {
    if (is_center[i]) {
      center_table[i] += (int)work_mem[pid * stride];
    }
  }

  memset(switch_membership + k1, 0, (k2 - k1) * sizeof(bool));
  memset(work_mem + pid * stride, 0, stride * sizeof(double));
  if (pid == 0)
    memset(work_mem + nproc * stride, 0, stride * sizeof(double));

#ifdef PROFILE
  double t1 = gettime();
  if (pid == 0)
    time_gain_init += t1 - t0;
#endif

  double *lower = &work_mem[pid * stride];
  double *gl_lower = &work_mem[nproc * stride];

  std::vector<unsigned char> sw_gpu;
  std::vector<double> costdiff_gpu;
  std::vector<int> lower_index_gpu;
  std::vector<double> lower_value_gpu;

  pgain_phase1_cuda(points, x, sw_gpu, costdiff_gpu, lower_index_gpu, lower_value_gpu);

  for (int i = (int)k1; i < k2; i++) {
    if (sw_gpu[i]) {
      switch_membership[i] = 1;
      cost_of_opening_x += costdiff_gpu[i];
    } else {
      int idx = lower_index_gpu[i];
      if (idx >= 0)
        lower[idx] += lower_value_gpu[i];
    }
  }

#ifdef PROFILE
  double t2 = gettime();
  if (pid == 0) {
    time_gain_dist += t2 - t1;
  }
#endif

  for (int i = (int)k1; i < k2; i++) {
    if (is_center[i]) {
      double low = z;
      for (int p = 0; p < nproc; p++) {
        low += work_mem[center_table[i] + p * stride];
      }
      gl_lower[center_table[i]] = low;

      if (low > 0) {
        ++number_of_centers_to_close;
        cost_of_opening_x -= low;
      }
    }
  }

  work_mem[pid * stride + K] = number_of_centers_to_close;
  work_mem[pid * stride + K + 1] = cost_of_opening_x;

  if (pid == 0) {
    gl_cost_of_opening_x = z;

    for (int p = 0; p < nproc; p++) {
      gl_number_of_centers_to_close += (int)work_mem[p * stride + K];
      gl_cost_of_opening_x += work_mem[p * stride + K + 1];
    }
  }

  if (gl_cost_of_opening_x < 0) {
    pgain_apply_cuda(points, x, switch_membership, gl_lower, stride);

    for (int i = (int)k1; i < k2; i++) {
      if (is_center[i] && gl_lower[center_table[i]] > 0) {
        is_center[i] = false;
      }
    }
    if (x >= k1 && x < k2) {
      is_center[x] = true;
    }

    if (pid == 0) {
      *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;
    }
  } else {
    if (pid == 0)
      gl_cost_of_opening_x = 0;
  }

  if (pid == 0) {
    free(work_mem);
  }

#ifdef PROFILE
  double t3 = gettime();
  if (pid == 0)
    time_gain += t3 - t0;
#endif

  return -gl_cost_of_opening_x;
}

float pFL(Points *points, int *feasible, int numfeasible, float z, long *k, double cost, long iter, float e,
          int pid, pthread_barrier_t *barrier) {
  long i;
  long x;
  double change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;

    if (pid == 0) {
      intshuffle(feasible, numfeasible);
    }

    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, pid, barrier);
      c++;
    }

    cost -= change;
#ifdef PRINTINFO
    if (pid == 0) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n", *k, cost, cost - z * (*k));
    }
#endif
  }
  return (float)cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t *barrier) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((double)kmin)))
    numfeasible = (int)(ITER * kmin * log((double)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  float *accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < k2; i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight = (float *)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }

  free(accumweight);

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal, int pid, pthread_barrier_t *barrier) {
  int i;
  double cost;
  double lastcost;
  double hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static double *hizs;

  if (pid == 0)
    hizs = (double *)calloc(nproc, sizeof(double));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num / nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if (pid == nproc - 1)
    k2 = points->num;

#ifdef PRINTINFO
  if (pid == 0) {
    printf("Starting Kmedian procedure\n");
    printf("%i points in %i dimensions\n", (int)numberOfPoints, (int)ptDimension);
  }
#endif

  double myhiz = 0;
  for (long kk = k1; kk < k2; kk++) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }
  hizs[pid] = myhiz;

  for (int i2 = 0; i2 < nproc; i2++) {
    hiz += hizs[i2];
  }

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
    for (long kk = k1; kk < k2; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if (pid == 0) {
      free(hizs);
      *kfinal = k;
    }
    return (float)cost;
  }

  if (pid == 0)
    shuffle(points);
  cost = pspeedy(points, (float)z, &k, pid, barrier);

#ifdef PRINTINFO
  if (pid == 0)
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n", pid, cost, (int)k);
#endif
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, (float)z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if (pid == 0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n", pid, cost, (int)k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    if (pid == 0) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    if (pid == 0)
      shuffle(points);
    cost = pspeedy(points, (float)z, &k, pid, barrier);
    i++;
  }

  if (pid == 0) {
    numfeasible = selectfeasible_fast(points, &feasible, (int)kmin, pid, barrier);
    for (int i2 = 0; i2 < points->num; i2++) {
      is_center[points->p[i2].assign] = true;
    }
  }

  while (1) {
    d++;
#ifdef PRINTINFO
    if (pid == 0) {
      printf("loz = %lf, hiz = %lf\n", loz, hiz);
      printf("Running Local Search...\n");
    }
#endif

    lastcost = cost;
    (void)lastcost;
    cost = pFL(points, feasible, numfeasible, (float)z, &k, cost,
               (long)(ITER * kmax * log((double)kmax)), 0.1f, pid, barrier);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) || ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      if (pid == 0) {
        printf("Trying a more accurate local search...\n");
      }
#endif
      cost = pFL(points, feasible, numfeasible, (float)z, &k, cost,
                 (long)(ITER * kmax * log((double)kmax)), 0.001f, pid, barrier);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
  }

  if (pid == 0) {
    free(feasible);
    free(hizs);
    *kfinal = k;
  }

  return (float)cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

struct pkmedian_arg_t {
  Points *points;
  long kmin;
  long kmax;
  long *kfinal;
  int pid;
  pthread_barrier_t *barrier;
};

void *localSearchSub(void *arg_) {
  pkmedian_arg_t *arg = (pkmedian_arg_t *)arg_;
  pkmedian(arg->points, arg->kmin, arg->kmax, arg->kfinal, arg->pid, arg->barrier);
  return NULL;
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  pkmedian_arg_t arg;
  arg.points = points;
  arg.kmin = kmin;
  arg.kmax = kmax;
  arg.kfinal = kfinal;
  arg.pid = 0;
  arg.barrier = NULL;
  localSearchSub(&arg);

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

class PStream {
public:
  virtual size_t read(float *dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) { n = n_; }
  size_t read(float *dest, int dim, int num) {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() { return 0; }
  int feof() { return n <= 0; }
  ~SimStream() {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char *filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float *dest, int dim, int num) {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() { return std::ferror(fp); }
  int feof() { return std::feof(fp); }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE *fp;
};

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
  FILE *fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int *is_a_median = (int *)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", (unsigned int)centerIDs[i]);
      fprintf(fp, "%lf\n", (double)centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", (double)centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
}

void streamCluster(PStream *stream, long kmin, long kmax, int dim, long chunksize, long centersize, char *outfile) {
  block = (float *)malloc(chunksize * dim * sizeof(float));
  float *centerBlock = (float *)malloc(centersize * dim * sizeof(float));
  long *centerIDs = (long *)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %d points\n", (int)numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (bool *)malloc(points.num * sizeof(bool));
    is_center = (bool *)calloc(points.num, sizeof(bool));
    center_table = (int *)malloc(points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (bool *)malloc(centers.num * sizeof(bool));
  is_center = (bool *)calloc(centers.num, sizeof(bool));
  center_table = (int *)malloc(centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
  int numthreads;
  c = 0;
  d = 0;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 10) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n", argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  numthreads = nproc;
  ompthreads = nproc;
  nproc = 1;
  (void)numthreads;
  (void)ompthreads;

  srand48(SEED);
  PStream *stream;
  if (n > 0) {
    stream = new SimStream(n);
  } else {
    stream = new FileStream(infilename);
  }

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

  double t2 = gettime();

  printf("time = %lf\n", t2 - t1);

  delete stream;

  printf("time pgain = %lf\n", time_gain);
  printf("time pgain_dist = %lf\n", time_gain_dist);
  printf("time pgain_init = %lf\n", time_gain_init);
  printf("time pselect = %lf\n", time_select_feasible);
  printf("time pspeedy = %lf\n", time_speedy);
  printf("time pshuffle = %lf\n", time_shuffle);
  printf("time localSearch = %lf\n", time_local_search);
  printf("loops=%d\n", d);

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  delete[] outfilename;
  delete[] infilename;
  return 0;
}
